const rules = (arr1, arr2, ucl, lcl, p1Sigma, p2Sigma, p3Sigma, m1Sigma, m2Sigma, m3Sigma) => {
    let len = arr1.length
    let resFormatted ={
        "In Control": new Array(len).fill(null),
        "Out Control": new Array(len).fill(null),
        "Rule 1": new Array(len).fill(null),
        "Rule 2": new Array(len).fill(null),
        "Rule 3": new Array(len).fill(null),
        "Rule 4": new Array(len).fill(null),
        "Rule 5": new Array(len).fill(null),
        "Rule 6": new Array(len).fill(null),
        "Rule 7": new Array(len).fill(null),
        "Rule 8": new Array(len).fill(null),
    }

    //////////// Rules Checking
    arr1.map((item, index) => {
        let valueFormatted = ""
        if (lcl[index] !== null) {
            item < lcl[index] ? resFormatted["In Control"][index] = item : valueFormatted = ""
        } else if (item > ucl[index]) {
            resFormatted["Out Control"][index] = item
        }

        if (item > p3Sigma[index] || item < m3Sigma[index]) {
            resFormatted["Rule 1"][index] = item
        }

        if (index > 7) {
            let currentDataSlice = arr2.slice(index - 5, index + 1)
            let rulesChecking = currentDataSlice.reduce((acc, x) => {
                return acc + x
            }, 0)

            rulesChecking === 9 || rulesChecking === 0
                ? resFormatted["Rule 2"][index] = item
                : valueFormatted = ""

        }

        if (index > 4) {
            let currentDataSlice = arr1.slice(index - 5, index + 1)
            let rulesChecking = currentDataSlice.reduce((acc, x, i) => {
                let val = i === 0
                    ? 0
                    : x > currentDataSlice[i - 1]
                        ? 1
                        : x < currentDataSlice[i - 1]
                            ? -1
                            : 0
                return acc + val
            }, 0)
            rulesChecking === -5 || rulesChecking === 5
                ? resFormatted["Rule 3"][index] = item
                : valueFormatted = ""
        }

        if (index > 12) {
            let currentDataSlice = arr2.slice(index - 13, index + 1).join("")
            currentDataSlice === "01010101010101" || currentDataSlice === "10101010101010"
                ? resFormatted["Rule 4"][index] = item
                : valueFormatted = ""
        }

        if (index > 1) {
            let currentDataSlice = arr1.slice(index - 2, index + 1)
            let rulesChecking = currentDataSlice.reduce((acc, x, i) => {
                let val = x > p2Sigma[index]
                    ? 1
                    : x < m2Sigma[index]
                        ? -1
                        : 0
                return acc + val
            }, 0)
            rulesChecking >= 2 || rulesChecking <= -2
                ? resFormatted["Rule 5"][index] = item
                : valueFormatted = ""
        }

        if (index > 3) {
            let currentDataSlice = arr1.slice(index - 4, index + 1)
            let rulesChecking = currentDataSlice.reduce((acc, x, i) => {
                let val = x > p1Sigma[index]
                    ? 1
                    : x < m1Sigma[index]
                        ? -1
                        : 0
                return acc + val
            }, 0)
            rulesChecking >= 4 || rulesChecking <= -4
                ? resFormatted["Rule 6"][index] = item
                : valueFormatted = ""
        }

        if (index > 13) {
            let currentDataSlice = arr1.slice(index - 14, index + 1)
            let rulesChecking1 = currentDataSlice.reduce((acc, x, i) => {
                let val = x > p1Sigma[index]
                    ? 1
                    : 0
                return acc + val
            }, 0)
            let rulesChecking2 = currentDataSlice.reduce((acc, x, i) => {
                let val = x < p2Sigma[index]
                    ? 1
                    : 0
                return acc + val
            }, 0)
            rulesChecking1 === 0 && rulesChecking2 === 0
                ? resFormatted["Rule 7"][index] = item
                : valueFormatted = ""
        }
        if (index > 6) {
            let currentDataSlice = arr1.slice(index - 7, index + 1)
            let rulesChecking1 = currentDataSlice.reduce((acc, x, i) => {
                let val = x > p1Sigma[index]
                    ? 1
                    : 0
                return acc + val
            }, 0)
            let rulesChecking2 = currentDataSlice.reduce((acc, x, i) => {
                let val = x < m1Sigma[index]
                    ? 1
                    : 0
                return acc + val
            }, 0)
            rulesChecking1 + rulesChecking2 === 8
                ? resFormatted["Rule 8"][index] = item
                : valueFormatted = ""
        }

    })

    return resFormatted
}
const histogram = (arr,usl,lsl) =>{
    let normalDistribution = (x, mean, standardDeviation) => {
        const variance = standardDeviation * standardDeviation;
        const numerator = Math.exp(-0.5 * ((x - mean) * (x - mean)) / variance);
        const denominator = standardDeviation * Math.sqrt(2 * Math.PI);
        return numerator / denominator;
    }
    let len = arr.length
    let sum = arr.reduce((acc,x)=>{
        return acc+x
    },0)
    let max = Math.max(...arr)
    let min = Math.min(...arr)
    let mean = sum / len
    let range = max - min
    let sumStd = arr.reduce((acc, x, i) => {
        return acc + (x ^ 2)
    }, 0)
    let std = Math.sqrt(sumStd / (len - 1))
    let column = Math.round(Math.sqrt(len))
    let width = range/column
    let histogram = []
    let xAxis = []
    for (let index =0 ; index<column; index++){
        histogram.push(arr.filter(item => item >= (min + index * width) && item <= (min + (index + 1) * width)).length)
        xAxis.push(`${min + index * width} - ${min + (index + 1) * width}`) 
    }
    let simgaY = []
    let simgaX = []
    for (let index = 0; index < column; index++) {
        let x = (3 - index*0.05)*std+mean
        simgaY.push(normalDistribution(x , mean,std))
        simgaX.push(x)
        }

    return {
        simgaX,
        simgaY,
        xAxis,
        histogram,
        usl,
        lsl
    }
}









const iMR = (datas, metadata, constantMr, constantUcl, usl, lsl) => {
    //////////// Init
    let meta = datas.map(item => { return item[metadata]})
    let arr = datas.map(item => { return item._value })
    //////////// Constant
    let constant1 = constantMr || 1.128
    let constant2 = constantUcl || 3.267
    let len = arr.length
    let sumMr = 0
    let mean = arr.reduce((accumulator, item) => {
        return accumulator + item
    }, 0) / len

    //////////// Data Result
    let mrResult = []
    let greaterThanMean = []

    //////////// Data Population
    arr.forEach((item, index) => {
        if (index === 0) {
            mrResult.push(0)
        } else {
            mrResult.push(Math.max(item , arr[index - 1])- Math.min(item , arr[index - 1]))
            sumMr = sumMr + Math.max(item , arr[index - 1])- Math.min(item , arr[index - 1]),
            greaterThanMean.push(item > mean ? 1 : 0)
        }
    });
    let mrBar = sumMr / len
    let iSigma = mrBar / constant1


    //////////// Function
    let result = {
        meta,
        series1: arr,
        series2: mrResult,
        mean: new Array(len).fill(mean),
        p1Sigma : new Array(len).fill(mean + 1 * iSigma),
        p2Sigma : new Array(len).fill(mean + 2 * iSigma),
        p3Sigma : new Array(len).fill(mean + 3 * iSigma),
        m1Sigma : new Array(len).fill(mean - 1 * iSigma),
        m2Sigma : new Array(len).fill(mean - 2 * iSigma),
        m3Sigma : new Array(len).fill(mean - 3 * iSigma),
        ucl : new Array(len).fill(constant2 * mrBar),
        lcl: new Array(len).fill(null),
    }
    let hist = histogram(msg.payload.series1, 12049.98, 11410.61)
    let resFormatted = rules(result.series1, greaterThanMean, result.ucl, result.lcl, result.p1Sigma, result.p2Sigma, result.p3Sigma, result.m1Sigma, result.m2Sigma, result.m3Sigma)
    return {
        ... resFormatted,
        ... result,
        ...hist
    }
}

