const histogram = (arr,usl,lsl) =>{
    let normalDistribution = (x, mean, standardDeviation) => {
        const variance = standardDeviation * standardDeviation;
        const numerator = Math.exp(-0.5 * ((x - mean) * (x - mean)) / variance);
        const denominator = standardDeviation * Math.sqrt(2 * Math.PI);
        return numerator / denominator;
    }
    let len = arr.length
    let sum = arr.reduce((acc,x)=>{
        return acc+x
    },0)
    let max = Math.max(...arr)
    let min = Math.min(...arr)
    let mean = sum / len
    let range = max - min
    let sumStd = arr.reduce((acc, x, i) => {
        return acc + (x ^ 2)
    }, 0)
    let std = Math.sqrt(sumStd / (len - 1))
    let column = Math.round(Math.sqrt(len))
    let width = range/column
    let histogram = []
    let xAxis = []
    for (let index =0 ; index<column; index++){
        histogram.push(arr.filter(item => item >= (min + index * width) && item <= (min + (index + 1) * width)).length)
        xAxis.push(`${min + index * width} - ${min + (index + 1) * width}`) 
    }
    let simgaY = []
    let simgaX = []
    for (let index = 0; index < column; index++) {
        let x = (3 - index*0.05)*std+mean
        simgaY.push(normalDistribution(x , mean,std))
        simgaX.push(x)
        }

    return {
        simgaX,
        simgaY,
        xAxis,
        histogram,
        usl,
        lsl
    }
}









const iMR = (datas, metadata, constantMr, constantUcl, usl, lsl) => {
    //////////// Init
    let meta = datas.map(item => { return item[metadata]})
    let arr = datas.map(item => { return item._value })
    //////////// Constant
    let constant1 = constantMr || 1.128
    let constant2 = constantUcl || 3.267
    let len = arr.length
    let sumMr = 0
    let mean = arr.reduce((accumulator, item) => {
        return accumulator + item
    }, 0) / len

    //////////// Data Result
    let mrResult = []
    let greaterThanMean = []

    //////////// Data Population
    arr.forEach((item, index) => {
        if (index === 0) {
            mrResult.push(0)
        } else {
            mrResult.push(Math.max(item , arr[index - 1])- Math.min(item , arr[index - 1]))
            sumMr = sumMr + Math.max(item , arr[index - 1])- Math.min(item , arr[index - 1]),
            greaterThanMean.push(item > mean ? 1 : 0)
        }
    });
    let mrBar = sumMr / len
    let iSigma = mrBar / constant1


    //////////// Function
    let result = {
        meta,
        series1: arr,
        series2: mrResult,
        mean: new Array(len).fill(mean),
        p1Sigma : new Array(len).fill(mean + 1 * iSigma),
        p2Sigma : new Array(len).fill(mean + 2 * iSigma),
        p3Sigma : new Array(len).fill(mean + 3 * iSigma),
        m1Sigma : new Array(len).fill(mean - 1 * iSigma),
        m2Sigma : new Array(len).fill(mean - 2 * iSigma),
        m3Sigma : new Array(len).fill(mean - 3 * iSigma),
        ucl : new Array(len).fill(constant2 * mrBar),
        lcl: new Array(len).fill(null),
    }
    let hist = histogram(msg.payload.series1, 12049.98, 11410.61)
    let resFormatted = rules(result.series1, greaterThanMean, result.ucl, result.lcl, result.p1Sigma, result.p2Sigma, result.p3Sigma, result.m1Sigma, result.m2Sigma, result.m3Sigma)
    return {
        ... resFormatted,
        ... result,
        ...hist
    }
}

