function groupBy(array, key) {
    return array.reduce((result, currentValue) => {
        // Use the key to group the array elements
        const groupKey = currentValue[key];
        if (!result[groupKey]) {
            result[groupKey] = [];
        }
        result[groupKey].push(currentValue);
        return result;
    }, {});
}

