        if (item < lcl) {
            resFormatted["In Control"][index] = item 
        } else if (item > ucl) {
            resFormatted["Out Control"][index] = item
        }

        if (item > p3Sigma || item < m3Sigma) {
            resFormatted["Rule 1"][index] = item
        }

        if (index > 7) {
            let currentDataSlice = arr2.slice(index - 5, index + 1)
            let rulesChecking = currentDataSlice.reduce((acc, x) => {
                return acc + x
            }, 0)

            rulesChecking === 9 || rulesChecking === 0
                ? resFormatted["Rule 2"][index] = item
