var conversion = msg.pro.pro_running.converted?.value || 0

resolution.map(type => {


    var finalResult ={}

    //[R]/////////////// Monitoring PRO Target as input PRO
    let andonPro = {
        efficiency : Number(msg.payload.summaryOEE[type][0].oee),
        targetAndon : Number(msg.pro.pro_running.target_production || 0),
        totalGood : Number(msg.payload.summaryOEE[type][0]._Good * conversion),
        totalTarget : Number(msg.payload.summaryOEE[type][0]._TargetProduction * conversion),
        totalReject : Number(msg.payload.summaryOEE[type][0]._Reject * conversion),
        totalRework : Number(msg.payload.summaryOEE[type][0]._Rework * conversion),
        totalDefect : Number(msg.payload.summaryOEE[type][0]._Defect * conversion),
        totalTotal : Number(msg.payload.summaryOEE[type][0]._Total * conversion),
        actual_cycle_time : Number(msg.payload.summaryOEE[type][0].avg_cycle_time * conversion ),
    }
    //[A]/////////////// Conversion PRO Target as Line
    let andonLine = {
        efficiency: andonPro.efficiency,
        targetAndon: conversion === 0 ? 0 : Number(andonPro.targetAndon / conversion),
        totalGood: conversion === 0 ? 0 : Number(andonPro.totalGood / conversion ),
        totalTarget: conversion === 0 ? 0 : Number(andonPro.totalTarget / conversion),
        totalReject :conversion === 0 ? 0 : Number(andonPro.totalReject / conversion), 
        totalRework :conversion === 0 ? 0 : Number(andonPro.totalRework / conversion), 
        totalDefect :conversion === 0 ? 0 : Number(andonPro.totalDefect / conversion), 
        totalTotal :conversion === 0 ? 0 : Number(andonPro.totalTotal / conversion), 
        actual_cycle_time :conversion === 0 ? 0 : Number(andonPro.actual_cycle_time / conversion), 
    }

    finalResult.andonPro = andonPro
    finalResult.andonLine = andonLine

    Object.keys(finalResult).map(resultData => {
        global.set(`live_status.${msg.topic}.dashboard_realtime["${resultData}"]`, finalResult[resultData])
    })
})

