const timeOutSettings = 60000;

// Function to handle HTTP requests
const handleHttpRequest = async (input) => {
    // let data = {...input}
    try {
        // Validate URL and method
        if (!input.url || !input.method) {
            throw new Error('URL and method are required.');
        }

        switch (input.method) {
            case "GET":
                return await makeRequest(input);
            case "POST":
                return await makeRequest(input);
            case "PUT":
                return await makeRequest(input);
            case "DELETE":
                return await makeRequest(input);
            case "PATCH":
                return await makeRequest(input);
            default:
                throw new Error(`Unsupported HTTP method: ${input.method}`);
        }
    } catch (error) {
        let dataError = error;
        return [{
            ...input,
            ...dataError.response,
            inputData: input.payload, // Use input.payload instead of data.payload
            error,
            statusCode: dataError.response?.status || 400,
            message: dataError.message,
            code: dataError.code,
        },{ x: 1 }]
    }
};

// Utility function to make an HTTP request
const makeRequest = async (input) => {
    const config = {
        url: input.url,
        method: input.method,
        data: input.payload,
        params: input.params,
        headers: input.headers,
        timeout: input.timeout || timeOutSettings,
    };
    // node.send(config)
    try {
        const response = await axios(config);
        return [updateInput(input, response), { x: 1 }];
    } catch (error) {
        // Add error property to the original input
        throw error; // Throw the modified input object with the error property
    }
};

// Utility function to update input with response data
const updateInput = (input, response) => {
    const { data, status, statusText, headers } = response;
    return {
        ...input,
        inptData: input.payload,
        payload: data,
        statusCode: status,
        statusText: statusText,
        headers: headers,
        reqConfig: response.config,
        response
    };
    // return {payload: "FAIZ"}
};

