function getWeekOfMonth(d) {
  const day = d.getUTCDate();
  const week = Math.ceil(day / 7);
  return week > 5 ? 5 : week;
}

function checkFullFilled(data, workflow_code = "WORKFLOW_DELIVERY_ORDER",activity_code = "DO_DELIVERED") {
  const workflows = global.get("WORKFLOW");
  let result = false;

  const workflow = workflows?.[workflow_code];
  if (!workflow) {
    node.error(`${workflow_code} tidak ditemukan`);
    return false;
  }

  const activities = workflow.workflow_versions?.[0]?.activities ?? [];
  const deliveredActivity = activities.find(
    (a) => a.activity_status_code === activity_code,
  );

  if (!deliveredActivity) return false;

  const orders = (data.deliveryOrders ?? [])
    // 1. skip planning
    .filter((item) => !item.is_planning)
    // 4. detail kosong → false (dibuang)
    .filter((item) => item?.submission_id?.activity_id?.activity_status_code)
    // ambil order activity
    .map((item) => {
      const currentActivity = activities.find(
        (a) =>
          a.activity_status_code ===
          item.submission_id.activity_id.activity_status_code,
      );
      return Number(currentActivity?.order);
    })
    // buang yang undefined
    .filter((order) => !isNaN(order));

  // tidak ada data valid
  if (orders.length === 0) {
    result = false;
  }
  // hanya 1 data
  else if (orders.length === 1) {
    result = orders[0] >= Number(deliveredActivity.order);
  }
  // lebih dari 1 data → semua harus valid
  else {
    result = orders.every(
      (order) => order >= Number(deliveredActivity.order),
    );
  }
  return result;
}

