let SO_CACHE = global.get("SALES_ORDER_CACHE") || {};
const inputList = Array.isArray(msg.payload) ? msg.payload : [msg.payload];
const transactionList = [];

// Loop native JavaScript
for (const raw of inputList) {
  if (!raw || !raw.id) continue;

  const newData = generateBucketData(raw);
  if (!newData) continue;

  const id = raw.id;
  let oldData = null;

  // Cek apakah ID ini sudah ada di Cache
  if (SO_CACHE[id]) {
    oldData = SO_CACHE[id];
  }

  // Masukkan ke antrian untuk diproses di node Aggregator
  transactionList.push({
    oldData: oldData ? JSON.parse(JSON.stringify(oldData)) : null, // Deep clone aman untuk snapshot oldData
    newData: newData
  });

  // Update Cache Lokal (Memory)
  SO_CACHE[id] = newData;
}

// --- 3. COMMIT & OUTPUT ---
global.set("SALES_ORDER_CACHE", SO_CACHE);

msg.payload = transactionList;
return msg;

