function formatCurrency(amount) {
    if (!amount && amount !== 0) return "-";
    const absAmount = Math.abs(amount);
    if (absAmount >= 1000000000) return "Rp " + fmtMiliar.format(amount / 1000000000) + " Miliar";
    if (absAmount >= 1000000) return "Rp " + fmtMiliar.format(amount / 1000000) + " Juta";
    return "Rp " + fmtStandard.format(amount);
}

