function updateMetric(bucket, amount, id, isRemoval, type) {
    if (!bucket) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData(type);
    bucket.TRACKER = bucket.TRACKER || {};

    const prevVal = bucket.TRACKER[id];
    const exists = prevVal !== undefined;
    let delta = 0;

    if (isRemoval) {
        if (exists) {
            delta = -1 * (type === 'revenue' ? prevVal : 1);
            delete bucket.TRACKER[id];
        }
    } else {
        const valToAdd = type === 'revenue' ? amount : 1;
        if (exists && type === 'revenue') {
            delta = amount - prevVal;
            bucket.TRACKER[id] = amount;
        } else if (!exists) {
            delta = valToAdd;
            bucket.TRACKER[id] = valToAdd;
        }
    }

    if (delta !== 0) {
        bucket.VALUE.raw = (bucket.VALUE.raw || 0) + delta;
        const raw = bucket.VALUE.raw;
        bucket.VALUE.data.value = type === 'revenue' ? formatCurrency(raw) : fmtStandard.format(raw);
        const sign = delta > 0 ? "+" : "";
        bucket.VALUE.data.subValue = `${sign}${type === 'revenue' ? formatCurrency(delta) : delta}`;
    }
}

function updateStatus(bucket, status, id, isRemoval) {
    if (!bucket) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData('status');
    if (!bucket.VALUE.COUNTS) bucket.VALUE.COUNTS = {};

    bucket.TRACKER = bucket.TRACKER || {};
    const prevStat = bucket.TRACKER[id];

    let oldS = null, newS = null;
    if (isRemoval && prevStat) {
        oldS = prevStat;
        delete bucket.TRACKER[id];
    } else if (!isRemoval) {
        if (prevStat !== status) {
            oldS = prevStat;
            newS = status;
            bucket.TRACKER[id] = status;
        } else if (!prevStat) {
            newS = status;
            bucket.TRACKER[id] = status;
        }
    }

    const counts = bucket.VALUE.COUNTS;
    if (oldS) {
        counts[oldS] = (counts[oldS] || 1) - 1;
        if (counts[oldS] <= 0) delete counts[oldS];
    }
    if (newS) {
        counts[newS] = (counts[newS] || 0) + 1;
    }

    bucket.VALUE.data = Object.entries(counts).map(([k, v]) => ({ name: k, value: v }));
}

function updateMaterial(bucket, items, isRemoval) {
    if (!bucket || !items || !items.length) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData('material');
    if (!bucket.VALUE.COUNTS) bucket.VALUE.COUNTS = {};

    const counts = bucket.VALUE.COUNTS;
    const mult = isRemoval ? -1 : 1;

    items.forEach(item => {
        const name = item.material_id?.name;
        const qty = Number(item.qty_request) || 0;
        if (name && qty > 0) {
            counts[name] = (counts[name] || 0) + (qty * mult);
            if (counts[name] <= 0) delete counts[name];
        }
    });

    bucket.VALUE.data = Object.entries(counts)
        .map(([k, v]) => ({ name: k, value: v }))
        .sort((a, b) => b.value - a.value)
        .slice(0, 10);
}

function updateLineChart(topicRoot, timeframeKey, targetKey, keys, label, color, topicMetricRoot) {
    if (!topicRoot[timeframeKey]) topicRoot[timeframeKey] = {};
    if (!topicRoot[timeframeKey][targetKey]) topicRoot[timeframeKey][targetKey] = createEmptyData('chart');

    const chartObj = topicRoot[timeframeKey][targetKey];
    const sourceObj = topicMetricRoot[timeframeKey][targetKey];

    if (!sourceObj) return;

    const seriesData = keys.map(k => (sourceObj[k] && sourceObj[k].VALUE) ? sourceObj[k].VALUE.raw : 0);

    chartObj.data = {
        label: sourceObj.VALUE.data.label || label,
        value: sourceObj.VALUE.data.value,
        subValue: sourceObj.VALUE.data.subValue,
        xAxis: keys,
        seriesData: [{ name: label, color: color, data: seriesData }]
    };
}

function updateOrderFill(bucket, id, isFulfilled, isRemoval) {
    if (!bucket) return;

    bucket.TOTAL = bucket.TOTAL || { raw: 0, TRACKER: {} };
    bucket.FULFILLED = bucket.FULFILLED || { raw: 0, TRACKER: {} };
    bucket.VALUE = bucket.VALUE || {
        raw: 0,
        prevRaw: 0, // ← simpan nilai sebelumnya
        data: { value: "0%", label: "0 / 0", subValue: "0%" }
    };

    // ===== SIMPAN NILAI SEBELUM UPDATE =====
    const prevPercent = Number(bucket.VALUE.raw) || 0;

    // ===== TOTAL & FULFILLED =====
    const existed = bucket.TOTAL.TRACKER[id];

    if (isRemoval) {
        if (existed) {
            bucket.TOTAL.raw--;
            delete bucket.TOTAL.TRACKER[id];

            if (bucket.FULFILLED.TRACKER[id]) {
                bucket.FULFILLED.raw--;
                delete bucket.FULFILLED.TRACKER[id];
            }
        }
    } else {
        if (!existed) {
            bucket.TOTAL.raw++;
            bucket.TOTAL.TRACKER[id] = true;

            if (isFulfilled) {
                bucket.FULFILLED.raw++;
                bucket.FULFILLED.TRACKER[id] = true;
            }
        } else {
            const wasFulfilled = !!bucket.FULFILLED.TRACKER[id];
            if (isFulfilled && !wasFulfilled) {
                bucket.FULFILLED.raw++;
                bucket.FULFILLED.TRACKER[id] = true;
            }
            if (!isFulfilled && wasFulfilled) {
                bucket.FULFILLED.raw--;
                delete bucket.FULFILLED.TRACKER[id];
            }
        }
    }

    // ===== HITUNG PERSENTASE =====
    const total = bucket.TOTAL.raw;
    const done = bucket.FULFILLED.raw;

    const percent = total === 0 ? 0 : +(done / total * 100).toFixed(1);
    const diff = +(percent - prevPercent).toFixed(1);

    // ===== SET VALUE =====
    bucket.VALUE.prevRaw = prevPercent;
    bucket.VALUE.raw = percent;

    bucket.VALUE.data.value = `${percent}%`;
    bucket.VALUE.data.label = `${done} / ${total}`;
    bucket.VALUE.data.subValue =
        diff > 0 ? `+${diff}%`
            : diff < 0 ? `${diff}%`
                : `0%`;
}

