function processSingle(data, isRemoval) {
    const { bucket, amount, id, status, items, customerCode, isFulFilled, isCurrentYear, isCurrentMonth, isCurrentWeek, isToday } = data;
    const { monthName, weekStr, dayName, hourStr } = bucket;

    // Definisikan timeframe beserta flag validasinya
    const updates = [
        ['YEARLY', monthName, ALL_MONTHS, "", isCurrentYear],
        ['MONTHLY', weekStr, ALL_WEEKS, "Week", isCurrentMonth],
        ['WEEKLY', dayName, ALL_DAYS, "", isCurrentWeek],
        ['DAILY', hourStr, ALL_HOURS, "Hour", isToday]
    ];

    const targets = [KEY_ALL];
    if (customerCode && customerCode !== "UNKNOWN") targets.push(customerCode);

    targets.forEach(targetKey => {
        updates.forEach(([tfKey, keyName, keysArr, lblPfx, isValidTimeframe]) => {

            // 1. PASTIKAN STRUKTUR (KEY) TERBUAT DULU (Walaupun isinya 0)
            ALL_TOPICS.forEach(topic => {
                if (!ROOT_SO[topic][tfKey]) ROOT_SO[topic][tfKey] = {};
            });

            // Init Container jika belum ada (Agar muncul nilai 0 / Rp 0)
            if (!ROOT_SO[TOPIC_REVENUE][tfKey][targetKey]) {
                ROOT_SO[TOPIC_REVENUE][tfKey][targetKey] = initContainer(keysArr, 'revenue', lblPfx);
                ROOT_SO[TOPIC_COUNT][tfKey][targetKey] = initContainer(keysArr, 'count', lblPfx);
                ROOT_SO[TOPIC_STATUS][tfKey][targetKey] = initContainer(keysArr, 'status', lblPfx);
                ROOT_SO[TOPIC_MATERIAL][tfKey][targetKey] = initContainer(keysArr, 'material', lblPfx);
                ROOT_SO[TOPIC_ORDER_FILL][tfKey][targetKey] = initContainer(keysArr, 'percent', lblPfx);
            }

            // 2. BARU CEK VALIDASI WAKTU (Hanya update angka jika waktunya tepat)
            if (isValidTimeframe) {
                // Execute Updates (Hanya jika datanya valid untuk timeframe ini)
                updateMetric(ROOT_SO[TOPIC_REVENUE][tfKey][targetKey][keyName], amount, id, isRemoval, 'revenue');
                updateMetric(ROOT_SO[TOPIC_REVENUE][tfKey][targetKey], amount, id, isRemoval, 'revenue'); 

                updateMetric(ROOT_SO[TOPIC_COUNT][tfKey][targetKey][keyName], amount, id, isRemoval, 'count');
                updateMetric(ROOT_SO[TOPIC_COUNT][tfKey][targetKey], amount, id, isRemoval, 'count');

                if (status) {
                    updateStatus(ROOT_SO[TOPIC_STATUS][tfKey][targetKey][keyName], status, id, isRemoval);
                    updateStatus(ROOT_SO[TOPIC_STATUS][tfKey][targetKey], status, id, isRemoval);
                }
                if (items) {
                    updateMaterial(ROOT_SO[TOPIC_MATERIAL][tfKey][targetKey][keyName], items, isRemoval);
                    updateMaterial(ROOT_SO[TOPIC_MATERIAL][tfKey][targetKey], items, isRemoval);
                }

                // Sync Charts (Hanya update chart jika data berubah)
                updateLineChart(ROOT_SO[TOPIC_LINE_REVENUE], tfKey, targetKey, keysArr, "Revenue", COLOR_BLUE, ROOT_SO[TOPIC_REVENUE]);
                updateLineChart(ROOT_SO[TOPIC_LINE_COUNT], tfKey, targetKey, keysArr, "Sales Order", COLOR_BLUE, ROOT_SO[TOPIC_COUNT]);

                updateOrderFill(
                    ROOT_SO[TOPIC_ORDER_FILL][tfKey][targetKey][keyName],
                    id, isFulFilled, isRemoval
                );
                updateOrderFill(
                    ROOT_SO[TOPIC_ORDER_FILL][tfKey][targetKey],
                    id, isFulFilled, isRemoval
                );
            }
            // Jika isValidTimeframe == false, kode akan melewati blok update di atas, 
            // TAPI struktur object (key DAILY/MONTHLY) sudah terbentuk di langkah no 1 dengan nilai default 0.
        });
    });
}

