const MONTH_NAMES = ["jan", "feb", "mar", "apr", "may", "jun", "jul", "aug", "sep", "oct", "nov", "dec"];
const DAYS = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
const now = new Date();

function isSameWeek(d1, d2) {
  const date1 = new Date(d1.getFullYear(), d1.getMonth(), d1.getDate());
  const date2 = new Date(d2.getFullYear(), d2.getMonth(), d2.getDate());
  date1.setDate(date1.getDate() - date1.getDay());
  date2.setDate(date2.getDate() - date2.getDay());
  return date1.getTime() === date2.getTime();
}

function generateBucketData(item) {
  const d = new Date(item.date);
  if (isNaN(d.getTime())) return null;

  return {
    bucket: {
      year: d.getUTCFullYear(),
      monthName: MONTH_NAMES[d.getUTCMonth()],
      dayOfMonthStr: String(d.getUTCDate()),
      dayName: DAYS[d.getUTCDay()],
      hourStr: String(d.getUTCHours())
    },
    amount: 1, // Delivery Order dihitung 1 per ID
    id: item.id,
    status: item.status || "Unknown",
    statusCode: item.statusCode || "UNKNOWN",
    deliveryDate: item.date,
    arriveDate: item.arrivalDate,
    customerCode: item.customerCode || "UNKNOWN",
    // FLAGS
    isToday: (d.getDate()===now.getDate() && d.getMonth()===now.getMonth() && d.getFullYear()===now.getFullYear()),
    isCurrentWeek: isSameWeek(d, now),
    isCurrentYear: d.getFullYear() === now.getFullYear(),
    // Optional Data
    submissionLogs: item.submissionLogs,
    deliveryCycleId: item.deliveryCycleId
  };
}

