    // Handle Delete Operation (CDC Delete)
    if (msg.cdc_op === 'd') {
        if (DO_CACHE[id]) {
            transactionList.push({
                oldData: DO_CACHE[id], // Hapus data lama
                newData: null
            });
            delete DO_CACHE[id];
        }
        continue;
    }

    const newData = generateBucketData(raw);
    if (!newData) continue;

    let oldData = null;
    if (msg.isRealtime && DO_CACHE[id]) {
         oldData = DO_CACHE[id];
    }

    transactionList.push({
        oldData: oldData ? JSON.parse(JSON.stringify(oldData)) : null,
        newData: newData
    });

    DO_CACHE[id] = newData;
}

