function generateXAxisFromMonth(monthName, year = new Date().getFullYear()) {
    const endDate = getEndDateFromMonth(monthName, year);
    if (!endDate) return [];

    const startDate = new Date(year, ALL_MONTHS.indexOf(monthName), 1);
    const result = [];

    const d = new Date(startDate);
    while (d <= endDate) {
        const day = String(d.getDate()).padStart(2, '0');
        const month = String(d.getMonth() + 1).padStart(2, '0');
        result.push(`${day}/${month}`);
        d.setDate(d.getDate() + 1);
    }
    return result;
}

function getWeekOfMonth(date) {
    const d = new Date(date);
    const dayOfMonth = d.getDate();

    if (dayOfMonth <= 7) return "1";
    if (dayOfMonth <= 14) return "2";
    if (dayOfMonth <= 21) return "3";
    if (dayOfMonth <= 28) return "4";
    return "5";
}


