// ===== DELIVERY CYCLE TIME CALCULATOR =====

/**
 * Calculate time difference from DO_OPEN to DO_DELIVERED_TO_CUSTOMER
 * Returns formatted string or null if activities missing
 */
function calculateDeliveryCycleTime(submissionLogs) {
    if (!submissionLogs || !Array.isArray(submissionLogs) || submissionLogs.length === 0) {
        return null;
    }

    let openActivity = null;
    let deliveredActivity = null;

    for (const log of submissionLogs) {
        const activityCode = log.activity_id?.activity_status_code;

        if (activityCode === 'DO_OPEN') {
            openActivity = log;
        } else if (activityCode === 'DO_DELIVERED_TO_CUSTOMER') {
            deliveredActivity = log;
        }

        if (openActivity && deliveredActivity) break;
    }

    if (!openActivity || !deliveredActivity) {
        return null;
    }

    const openDate = new Date(openActivity.date_created);
    const deliveredDate = new Date(deliveredActivity.date_created);

    if (isNaN(openDate.getTime()) || isNaN(deliveredDate.getTime())) {
        return null;
    }

    const diffMs = Number(deliveredDate) - Number(openDate);
    if (diffMs < 0) return null;

    const diffMinutes = Math.floor(diffMs / (1000 * 60));
    const diffHours = Math.floor(diffMs / (1000 * 60 * 60));
    const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
    const diffWeeks = Math.floor(diffDays / 7);
    const diffMonths = Math.floor(diffDays / 30);
    const diffYears = Math.floor(diffDays / 365);

    if (diffYears > 0) {
        return diffYears === 1 ? "1 tahun" : `${diffYears} tahun`;
    } else if (diffMonths > 0) {
        return diffMonths === 1 ? "1 bulan" : `${diffMonths} bulan`;
    } else if (diffWeeks > 0) {
        return diffWeeks === 1 ? "1 minggu" : `${diffWeeks} minggu`;
    } else if (diffDays > 0) {
        return diffDays === 1 ? "1 hari" : `${diffDays} hari`;
    } else if (diffHours > 0) {
        return diffHours === 1 ? "1 jam" : `${diffHours} jam`;
    } else if (diffMinutes > 0) {
        return diffMinutes === 1 ? "1 menit" : `${diffMinutes} menit`;
    } else {
        return "< 1 menit";
    }
}

function getLeadTimeRange(submissionLogs) {
    if (!submissionLogs || !Array.isArray(submissionLogs) || submissionLogs.length === 0) {
        return null;
    }

    let openActivity = null;
    let deliveredActivity = null;

    for (const log of submissionLogs) {
        const activityCode = log.activity_id?.activity_status_code;

        if (activityCode === 'DO_OPEN') {
            openActivity = log;
        } else if (activityCode === 'DO_DELIVERED_TO_CUSTOMER') {
            deliveredActivity = log;
        }

        if (openActivity && deliveredActivity) break;
    }

    if (!openActivity || !deliveredActivity) {
        return null;
    }

    const openDate = new Date(openActivity.date_created);
    const deliveredDate = new Date(deliveredActivity.date_created);

    if (isNaN(openDate.getTime()) || isNaN(deliveredDate.getTime())) {
        return null;
    }

    const diffMs = Number(deliveredDate) - Number(openDate);
    if (diffMs < 0) return null;

    const diffHours = diffMs / (1000 * 60 * 60);
    const diffDays = diffMs / (1000 * 60 * 60 * 24);

    // Categorize into ranges
    if (diffHours < 1) {
        return "< 1 jam";
    } else if (diffHours < 6) {
        return "1-6 jam";
    } else if (diffHours < 12) {
        return "6-12 jam";
    } else if (diffHours < 24) {
        return "12-24 jam";
    } else if (diffDays < 3) {
        return "1-2 hari";
    } else if (diffDays < 7) {
        return "3-7 hari";
    } else {
        return "> 1 minggu";
    }
}

