function updateMetric(bucket, amount, id, isRemoval) {
    if (!bucket) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData('count');
    bucket.TRACKER = bucket.TRACKER || {};

    const prevVal = bucket.TRACKER[id];
    const exists = prevVal !== undefined;
    let delta = 0;

    if (isRemoval) {
        if (exists) {
            delta = -1 * prevVal;
            delete bucket.TRACKER[id];
        }
    } else {
        const valToAdd = 1;
        if (exists) {
            delta = 0;
        } else {
            delta = valToAdd;
            bucket.TRACKER[id] = valToAdd;
        }
    }

    if (delta !== 0) {
        bucket.VALUE.raw = (bucket.VALUE.raw || 0) + delta;
        bucket.VALUE.data.value = formatCount(bucket.VALUE.raw);
        bucket.VALUE.data.subValue = "(Data Updated)";
    }
}

function updateStatus(bucket, status, id, isRemoval) {
    if (!bucket) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData('status');
    if (!bucket.VALUE.COUNTS) bucket.VALUE.COUNTS = {};
    bucket.TRACKER = bucket.TRACKER || {};

    const prevStat = bucket.TRACKER[id];
    let oldS = null, newS = null;

    if (isRemoval && prevStat) {
        oldS = prevStat;
        delete bucket.TRACKER[id];
    } else if (!isRemoval) {
        if (prevStat !== status) {
            oldS = prevStat;
            newS = status;
            bucket.TRACKER[id] = status;
        } else if (!prevStat) {
            newS = status;
            bucket.TRACKER[id] = status;
        }
    }

    const counts = bucket.VALUE.COUNTS;
    if (oldS) { counts[oldS] = (counts[oldS] || 1) - 1; if (counts[oldS] <= 0) delete counts[oldS]; }
    if (newS) { counts[newS] = (counts[newS] || 0) + 1; }

    bucket.VALUE.data = Object.keys(counts).map(key => ({
        name: key,
        value: counts[key],
        color: STATUS_COLORS[key] || DEFAULT_COLOR
    })).filter(item => item.value > 0).sort((a,b) => b.value - a.value);
}

function updateOtif(bucket, arriveDate, deliveryDate, id, isRemoval, deliveryCycleId) {
    if (!bucket) return;

    bucket.VALUE = bucket.VALUE || {};
    bucket.VALUE.onTime = bucket.VALUE.onTime ?? 0;
    bucket.VALUE.totalDelivered = bucket.VALUE.totalDelivered ?? 0;
    bucket.VALUE.data = bucket.VALUE.data || {
        label: "This Month",
        onTime: 0,
        totalDelivered: 0
    };

    bucket.TRACKER = bucket.TRACKER || {};

    let isOnTime = false;

    if (arriveDate && deliveryDate) {
        const tolerance = deliveryCycleId?.tolerance || 0;
        const delivery = new Date(deliveryDate);
        if (tolerance) {
            delivery.setMinutes(delivery.getMinutes() + tolerance);
        }
        const arrive = new Date(arriveDate);

        if (!isNaN(arrive) && !isNaN(delivery)) {
            isOnTime = arrive <= delivery;
        }
    }

    const prev = bucket.TRACKER[id];

    if (isRemoval) {
        if (prev) {
            bucket.VALUE.totalDelivered = Math.max(0, bucket.VALUE.totalDelivered - 1);
            if (prev.isOnTime) {
                bucket.VALUE.onTime = Math.max(0, bucket.VALUE.onTime - 1);
            }
            delete bucket.TRACKER[id];
        }
    } else {
        if (!prev) {
            bucket.VALUE.totalDelivered += 1;
            if (isOnTime) bucket.VALUE.onTime += 1;
            bucket.TRACKER[id] = { isOnTime };
        } 
        else if (prev.isOnTime !== isOnTime) {
            if (prev.isOnTime) {
                bucket.VALUE.onTime = Math.max(0, bucket.VALUE.onTime - 1);
            }
            if (isOnTime) {
                bucket.VALUE.onTime += 1;
            }
            bucket.TRACKER[id].isOnTime = isOnTime;
        }
    }

    bucket.VALUE.data.onTime = bucket.VALUE.onTime || 0;
    bucket.VALUE.data.totalDelivered = bucket.VALUE.totalDelivered || 0;
}

function updateDeliveredPerUser(bucket, { id, customerName, customerCode }, isRemoval) {
    if (!bucket) return;

    if (!bucket.VALUE) {
        bucket.VALUE = { data: [] };
    }
    bucket.TRACKER = bucket.TRACKER || {};
    bucket.COUNTS = bucket.COUNTS || {};

    const finalCustomerName = customerName || "Unknown Customer";
    const finalCustomerCode = customerCode || "UNKNOWN";

    const prev = bucket.TRACKER[id];

    if (isRemoval && prev) {
        const key = prev.customerCode;
        if (bucket.COUNTS[key]) {
            bucket.COUNTS[key].count = Math.max(0, bucket.COUNTS[key].count - 1);
            if (bucket.COUNTS[key].count === 0) {
                delete bucket.COUNTS[key];
            }
        }
        delete bucket.TRACKER[id];
    }

    if (!isRemoval && !prev) {
        const key = finalCustomerCode;
        if (!bucket.COUNTS[key]) {
            bucket.COUNTS[key] = {
                customerName: finalCustomerName,
                customerCode: finalCustomerCode,
                count: 0
            };
        }
        bucket.COUNTS[key].count += 1;
        bucket.TRACKER[id] = {
            customerName: finalCustomerName,
            customerCode: finalCustomerCode
        };
    }

    if (!isRemoval && prev && prev.customerCode !== finalCustomerCode) {
        const oldKey = prev.customerCode;
        if (bucket.COUNTS[oldKey]) {
            bucket.COUNTS[oldKey].count = Math.max(0, bucket.COUNTS[oldKey].count - 1);
            if (bucket.COUNTS[oldKey].count === 0) {
                delete bucket.COUNTS[oldKey];
            }
        }

        const newKey = finalCustomerCode;
        if (!bucket.COUNTS[newKey]) {
            bucket.COUNTS[newKey] = {
                customerName: finalCustomerName,
                customerCode: finalCustomerCode,
                count: 0
            };
        }
        bucket.COUNTS[newKey].count += 1;
        bucket.TRACKER[id] = {
            customerName: finalCustomerName,
            customerCode: finalCustomerCode
        };
    }

    bucket.VALUE.data = Object.values(bucket.COUNTS)
        .filter(item => item.count > 0)
        .sort((a, b) => b.count - a.count);
}


function updateLeadTime(bucket, { id, leadTimeRange, cycleTime }, isRemoval) {
    if (!bucket || !leadTimeRange) return;

    if (!bucket.VALUE) {
        bucket.VALUE = { data: [] };
    }
    bucket.TRACKER = bucket.TRACKER || {};
    bucket.COUNTS = bucket.COUNTS || {};

    const prev = bucket.TRACKER[id];

    // REMOVE
    if (isRemoval && prev) {
        const key = prev.leadTimeRange;
        if (bucket.COUNTS[key]) {
            bucket.COUNTS[key].count = Math.max(0, bucket.COUNTS[key].count - 1);
            if (bucket.COUNTS[key].count === 0) {
                delete bucket.COUNTS[key];
            }
        }
        delete bucket.TRACKER[id];
    }

    // ADD
    if (!isRemoval && !prev) {
        const key = leadTimeRange;
        if (!bucket.COUNTS[key]) {
            bucket.COUNTS[key] = {
                range: leadTimeRange,
                count: 0
            };
        }
        bucket.COUNTS[key].count += 1;
        bucket.TRACKER[id] = {
            leadTimeRange,
            cycleTime
        };
    }

    // UPDATE (if range changed)
    if (!isRemoval && prev && prev.leadTimeRange !== leadTimeRange) {
        const oldKey = prev.leadTimeRange;
        if (bucket.COUNTS[oldKey]) {
            bucket.COUNTS[oldKey].count = Math.max(0, bucket.COUNTS[oldKey].count - 1);
            if (bucket.COUNTS[oldKey].count === 0) {
                delete bucket.COUNTS[oldKey];
            }
        }

        const newKey = leadTimeRange;
        if (!bucket.COUNTS[newKey]) {
            bucket.COUNTS[newKey] = {
                range: leadTimeRange,
                count: 0
            };
        }
        bucket.COUNTS[newKey].count += 1;
        bucket.TRACKER[id] = {
            leadTimeRange,
            cycleTime
        };
    }

    // SYNC OUTPUT ARRAY (sorted by longest lead time first - DESCENDING)
    bucket.VALUE.data = LEAD_TIME_RANGES
        .map(range => {
            const item = bucket.COUNTS[range];
            return {
                range: range,
                count: item ? item.count : 0
            };
        })
        .filter(item => item.count > 0)
        .reverse();  // Reverse to show longest first
}


function updateDeliveryQtyTrend(
