        xAxis = ALL_MONTHS.map(m => m.charAt(0).toUpperCase() + m.slice(1));
        bucket.VALUE.data.xAxis = xAxis;

        const d = new Date(deliveryDate);
        if (!isNaN(d)) {
            const monthIdx = d.getMonth();
            dateKey = ALL_MONTHS[monthIdx];
            dateIndex = monthIdx;
        }
    } else if (timeframeKey === 'WEEKLY') {
        xAxis = ALL_DAYS.map(d => d.charAt(0).toUpperCase() + d.slice(1));
        bucket.VALUE.data.xAxis = xAxis;

        const d = new Date(deliveryDate);
        if (!isNaN(d)) {
            dateIndex = d.getDay();
        }
    } else if (timeframeKey === 'DAILY') {
        xAxis = ALL_HOURS;
        bucket.VALUE.data.xAxis = xAxis;

        const d = new Date(deliveryDate);
        if (!isNaN(d)) {
            dateIndex = d.getHours();
        }
    }

    if (dateIndex === -1 || xAxis.length === 0) return;

    if (!customerName || customerName === "UNKNOWN") {
        customerName = "Unknown Customer";
    }

    const prev = bucket.TRACKER[id];

    let series = bucket.VALUE.data.seriesData.find(s => s.name === customerName);

    if (!series) {
        series = {
            name: customerName,
            color: pickColor(customerName),
            data: new Array(xAxis.length).fill(0)
        };
        bucket.VALUE.data.seriesData.push(series);
    }

    if (isRemoval && prev) {
        series.data[prev.dateIndex] = Math.max(0, series.data[prev.dateIndex] - prev.qty);
        delete bucket.TRACKER[id];

        if (series.data.every(v => v === 0)) {
            const idx = bucket.VALUE.data.seriesData.indexOf(series);
            if (idx > -1) bucket.VALUE.data.seriesData.splice(idx, 1);
        }
    }

    if (!isRemoval && !prev) {
        series.data[dateIndex] += qty;
        bucket.TRACKER[id] = { customerName, qty, dateIndex };
    }

    if (!isRemoval && prev && prev.qty !== qty) {
        series.data[prev.dateIndex] = Math.max(0, series.data[prev.dateIndex] - prev.qty);
        series.data[dateIndex] += qty;
        bucket.TRACKER[id] = { customerName, qty, dateIndex };
    }
}

function getTimeframeLabel(timeframeKey) {
    const labels = {
        'YEARLY': 'This Year',
        'MONTHLY': 'This Month',
        'WEEKLY': 'This Week',
        'DAILY': 'Today'
    };
    return labels[timeframeKey] || 'This Period';
}


function syncBarChart(topicRoot, timeframeKey, keys, label) {
    const bucketAll = topicRoot[KEY_ALL];
    if(!bucketAll) return;

    const seriesValues = keys.map(k => {
        return (bucketAll[k] && bucketAll[k].VALUE) ? bucketAll[k].VALUE.raw : 0;
    });

    const summaryData = bucketAll.VALUE.data;
    summaryData.xAxis = keys;
    summaryData.seriesData = [{
        name: label,
        data: seriesValues,
        color: COLOR_DELIVERED_BAR
    }];
}

function getNestedTimeframeKey(parentTimeframe) {
    const mapping = {
        'YEARLY': 'MONTHLY',
        'MONTHLY': 'WEEKLY',
        'WEEKLY': 'DAILY',
        'DAILY': 'DAILY'
    };
    return mapping[parentTimeframe] || 'DAILY';
}

// --- 5. PROCESS SINGLE ---
function processSingle(data, isRemoval) {
    const { bucket, amount, id, status, statusCode, deliveryDate, arriveDate, customerCode, customerName, qty, deliveryCycleId, submissionLogs } = data;
    const { year, monthName, dayOfMonthStr, dayName, hourStr } = bucket;
    const activityCodeOrder = mapStatusCodeToOrder("WORKFLOW_DELIVERY_ORDER")

    //  Calculate cycle time and lead time range
    const cycleTime = calculateDeliveryCycleTime(submissionLogs);
    const leadTimeRange = getLeadTimeRange(submissionLogs);

    // Add to data for reference
    // if (!isRemoval) {
    //     data.cycleTime = cycleTime;
    //     data.leadTimeRange = leadTimeRange;
    // }

    const weekOfMonth = getWeekOfMonth(deliveryDate);

    const updates = [
        ['YEARLY', monthName, ALL_MONTHS],
        ['MONTHLY', weekOfMonth, ALL_WEEKS],
        ['WEEKLY', dayName, ALL_DAYS],
        ['DAILY', hourStr, ALL_HOURS]
    ];

    const targetKey = "ALL";

    updates.forEach(([tfKey, keyName, keysArr]) => {
        ALL_TOPICS.forEach(topic => { if(!ROOT_DO[topic][tfKey]) ROOT_DO[topic][tfKey] = {}; });

        if (!ROOT_DO[TOPIC_TOTAL][tfKey][targetKey]) {
            ROOT_DO[TOPIC_TOTAL][tfKey][targetKey]              = initContainer(keysArr, 'count', tfKey === 'MONTHLY' ? 'Week' : '');
            ROOT_DO[TOPIC_PIE][tfKey][targetKey]                = initContainer(keysArr, 'status');
            ROOT_DO[TOPIC_OTIF][tfKey][targetKey]               = initContainer(keysArr, 'status');
            ROOT_DO[TOPIC_BAR][tfKey][targetKey]                = initContainer(keysArr, 'count', tfKey === 'MONTHLY' ? 'Week' : '');
            ROOT_DO[TOPIC_DELIVERY_QTY_TREND][tfKey][targetKey] = initContainer(keysArr, 'count', tfKey === 'MONTHLY' ? 'Week' : '');
            ROOT_DO[TOPIC_DELIVERED_PER_USER][tfKey][targetKey] = initContainer(keysArr, 'user_stats');
            ROOT_DO[TOPIC_DETAIL_LEAD_TIME][tfKey][targetKey]   = initContainer(keysArr, 'lead_time');
        }

        if (!ROOT_DO[TOPIC_DELIVERY_QTY_TREND][tfKey][targetKey][keyName]) {
            ROOT_DO[TOPIC_DELIVERY_QTY_TREND][tfKey][targetKey][keyName] = initDeliveryQtyTrend(
                tfKey === 'MONTHLY' ? `Week ${keyName}` : keyName,
                monthName,
                year
            );
        }

        if (!ROOT_DO[TOPIC_DELIVERED_PER_USER][tfKey][targetKey][keyName]) {
            ROOT_DO[TOPIC_DELIVERED_PER_USER][tfKey][targetKey][keyName] = initDeliveredPerUser();
        }

        if (!ROOT_DO[TOPIC_DETAIL_LEAD_TIME][tfKey][targetKey][keyName]) {
            ROOT_DO[TOPIC_DETAIL_LEAD_TIME][tfKey][targetKey][keyName] = initLeadTime();
        }

        // 1. Update Total
        updateMetric(ROOT_DO[TOPIC_TOTAL][tfKey][targetKey][keyName], amount, id, isRemoval);
        updateMetric(ROOT_DO[TOPIC_TOTAL][tfKey][targetKey], amount, id, isRemoval);

        // 2. Update Pie
        if (status) {
            updateStatus(ROOT_DO[TOPIC_PIE][tfKey][targetKey][keyName], status, id, isRemoval);
            updateStatus(ROOT_DO[TOPIC_PIE][tfKey][targetKey], status, id, isRemoval);
        }

        // 3. Update Bar (DO_DELIVERED Only)
        if (statusCode === 'DO_DELIVERED') {
            updateMetric(ROOT_DO[TOPIC_BAR][tfKey][targetKey][keyName], amount, id, isRemoval);
            updateMetric(ROOT_DO[TOPIC_BAR][tfKey][targetKey], amount, id, isRemoval);

            if (tfKey === 'MONTHLY') {
                syncBarChart(ROOT_DO[TOPIC_BAR][tfKey], targetKey, ALL_WEEKS.map(w => `Week ${w}`), "Total Delivered");
            } else {
                syncBarChart(ROOT_DO[TOPIC_BAR][tfKey], targetKey, keysArr, "Total Delivered");
            }

            updateDeliveredPerUser(
                ROOT_DO[TOPIC_DELIVERED_PER_USER][tfKey][targetKey],
                {
                    id: id,
                    customerName: customerName || customerCode || "Unknown Customer",
                    customerCode: customerCode || "UNKNOWN"
                },
                isRemoval
            );

            updateDeliveredPerUser(
                ROOT_DO[TOPIC_DELIVERED_PER_USER][tfKey][targetKey][keyName],
                {
                    id: id,
                    customerName: customerName || customerCode || "Unknown Customer",
                    customerCode: customerCode || "UNKNOWN"
                },
                isRemoval
            );
        }

        // 4. Update OTIF
        if (Number(activityCodeOrder[statusCode]) >= activityCodeOrder["DO_DELIVERED_TO_CUSTOMER"] ) {
            updateOtif(ROOT_DO[TOPIC_OTIF][tfKey][targetKey][keyName], arriveDate, deliveryDate, id, isRemoval, deliveryCycleId);
            updateOtif(ROOT_DO[TOPIC_OTIF][tfKey][targetKey], arriveDate, deliveryDate, id, isRemoval, deliveryCycleId);
        }

        // 5. Update Delivery Qty Trend
        updateDeliveryQtyTrend(
            ROOT_DO[TOPIC_DELIVERY_QTY_TREND][tfKey][targetKey],
            {
                id: id,
                customerName: customerName || customerCode || "Unknown Customer",
                qty: qty || 1,
                deliveryDate: deliveryDate,
                monthName: monthName,
                year: year,
                timeframeKey: tfKey
            },
            isRemoval
        );

        updateDeliveryQtyTrend(
            ROOT_DO[TOPIC_DELIVERY_QTY_TREND][tfKey][targetKey][keyName],
            {
                id: id,
                customerName: customerName || customerCode || "Unknown Customer",
                qty: qty || 1,
                deliveryDate: deliveryDate,
                monthName: monthName,
                year: year,
                timeframeKey: getNestedTimeframeKey(tfKey)
            },
            isRemoval
        );


        if (leadTimeRange && cycleTime) {
            updateLeadTime(
                ROOT_DO[TOPIC_DETAIL_LEAD_TIME][tfKey][targetKey],
                {
                    id: id,
                    leadTimeRange: leadTimeRange,
                    cycleTime: cycleTime
                },
                isRemoval
            );

            updateLeadTime(
                ROOT_DO[TOPIC_DETAIL_LEAD_TIME][tfKey][targetKey][keyName],
                {
                    id: id,
                    leadTimeRange: leadTimeRange,
                    cycleTime: cycleTime
                },
                isRemoval
            );
        }
    });
}

