flow.set("WORKFLOW.FUNCTION.ORDER_FILL", (data , workflow_code = "WORKFLOW_DELIVERY_ORDER" , activity_code = "DO_DELIVERED") =>{
    const workflows = global.get("WORKFLOW");
    // =====================
    // CONFIG
    // =====================
    const WORKFLOW_CODE = workflow_code;
    const ACTIVITY_CODE = activity_code;

    // =====================
    // 1. Ambil order workflow DELIVERY
    // =====================
    const deliveryWorkflowOrder = workflows[WORKFLOW_CODE]?.order;

    if (deliveryWorkflowOrder == null) {
        node.error(`${WORKFLOW_CODE} tidak ditemukan`);
        return false;
    }

    // =====================
    // 2. Ambil workflow & activity transaksi
    // =====================
    const workflowCode = data.submission.workflowStatus;
    const activityCode = data.submission.activityStatus;

    const workflow = workflows[workflowCode];
    if (!workflow) {
        return false;
    }

    const workflowOrder = workflow.order;

    // =====================
    // 3. Kondisi 1 -> jika status workflow udah di sales order
    // =====================
    // if (workflowOrder > deliveryWorkflowOrder) {
    //     return true;
    // }

    // =====================
    // 4. Kondisi 2 (DELIVERY ORDER)
    // =====================
    if (workflowOrder === deliveryWorkflowOrder) {

        const activities =
            workflow.workflow_versions?.[0]?.activities || [];

        const currentActivity = activities.find(
            a => a.activity_status_code === activityCode
        );

        const deliveredActivity = activities.find(
            a => a.activity_status_code === ACTIVITY_CODE
        );

        if (!currentActivity || !deliveredActivity) {
            return false;
        }

        return Number(currentActivity.order) >= Number(deliveredActivity.order);;
    }

    // =====================
    // 5. Default FALSE
    // =====================
    return false;
})

