function initContainer(keys, type, labelPrefix = "") {
    if (type === 'chart') return createEmptyData('chart');

    const container = { VALUE: createEmptyData(type) };
    if (keys) {
        keys.forEach(k => {
            container[k] = {
                VALUE: createEmptyData(type),
                TRACKER: {}
            };
            if (type !== 'status' && type !== 'material' && container[k].VALUE.data) {
                container[k].VALUE.data.label = labelPrefix ? `${labelPrefix} ${k}` : k;
            }
        });
    }
    return container;
}

function checkSubmissionStatus(submission, expected) {
    return (submission?.activityStatus === expected ? 1 : 0);
}

function checkFlag(flag, expected) {
    return flag.find(item => item?.flag_id?.code === expected)?.flag_id
}

function checkOntime(plannedDate, referenceDate) {
    if (!plannedDate || !referenceDate) {
        return {
            isOntime: false,
            diffDays: 0
        };
    }
    // normalize ke YYYY-MM-DD
    const planned = plannedDate.slice(0, 10);
    const reference = referenceDate.slice(0, 10);

    // convert ke Date (jam diset 00:00 biar harian murni)
    const dPlanned = new Date(planned + "T00:00:00");
    const dRef = new Date(reference + "T00:00:00");

    // selisih hari
    const diffDays = Math.floor(
        (dPlanned - dRef) / (1000 * 60 * 60 * 24)
    );

    return {
        isOntime: diffDays > 0, // planned lebih besar = on time
        diffDays: diffDays      // positif = lebih cepat, 0 = sama hari, negatif = telat
    };
}


function getOrderFromSubmission(workflow_code, activity_code) {
    const workflows = global.get("WORKFLOW");
    const workflow = workflows?.[workflow_code];
    if (!workflow) {
        node.error(`${workflow_code} tidak ditemukan`);
        return false;
    }

    const activities = workflow.workflow_versions?.[0]?.activities ?? [];
    const actifity = activities.find(
        (a) => a.activity_status_code === activity_code,
    );

    return actifity;
}

