// --- 4. CORE UPDATE FUNCTIONS ---

function updateMetric(bucket, amount, id, isRemoval, type) {
    if (!bucket) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData(type);
    bucket.TRACKER = bucket.TRACKER || {};

    const prevVal = bucket.TRACKER[id];
    const exists = prevVal !== undefined;
    let delta = 0;

    if (isRemoval) {
        if (exists) {
            delta = -1 * (type === 'revenue' ? prevVal : 1);
            delete bucket.TRACKER[id];
        }
    } else {
        const valToAdd = type === 'revenue' ? amount : 1;
        if (exists && type === 'revenue') {
            delta = amount - prevVal;
            bucket.TRACKER[id] = amount;
        } else if (!exists) {
            delta = valToAdd;
            bucket.TRACKER[id] = valToAdd;
        }
    }

    if (delta !== 0) {
        bucket.VALUE.raw = (bucket.VALUE.raw || 0) + delta;
        const raw = bucket.VALUE.raw;
        bucket.VALUE.data.value = type === 'revenue' ? formatCurrency(raw) : fmtStandard.format(raw);
        const sign = delta > 0 ? "+" : "";
        bucket.VALUE.data.subValue = `${sign}${type === 'revenue' ? formatCurrency(delta) : delta}`;
    }
}

function updateStatus(bucket, status, id, isRemoval) {
    if (!bucket) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData('status');
    if (!bucket.VALUE.COUNTS) bucket.VALUE.COUNTS = {};

    bucket.TRACKER = bucket.TRACKER || {};
    const prevStat = bucket.TRACKER[id];

    let oldS = null, newS = null;
    if (isRemoval && prevStat) {
        oldS = prevStat;
        delete bucket.TRACKER[id];
    } else if (!isRemoval) {
        if (prevStat !== status) {
            oldS = prevStat;
            newS = status;
            bucket.TRACKER[id] = status;
        } else if (!prevStat) {
            newS = status;
            bucket.TRACKER[id] = status;
        }
    }

    const counts = bucket.VALUE.COUNTS;
    if (oldS) {
        counts[oldS] = (counts[oldS] || 1) - 1;
        if (counts[oldS] <= 0) delete counts[oldS];
    }
    if (newS) {
        counts[newS] = (counts[newS] || 0) + 1;
    }

    bucket.VALUE.data = Object.entries(counts).map(([k, v]) => ({ name: k, value: v }));
}

function updateMaterial(bucket, items, isRemoval) {
    if (!bucket || !items || !items.length) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData('material');
    if (!bucket.VALUE.COUNTS) bucket.VALUE.COUNTS = {};

    const counts = bucket.VALUE.COUNTS;
    const mult = isRemoval ? -1 : 1;

    items.forEach(item => {
        const name = item.material_id?.name;
        const qty = Number(item.qty) || 0;
        if (name && qty > 0) {
            counts[name] = (counts[name] || 0) + (qty * mult);
            if (counts[name] <= 0) delete counts[name];
        }
    });

    bucket.VALUE.data = Object.entries(counts)
        .map(([k, v]) => ({ name: k, value: v }))
        .sort((a, b) => b.value - a.value)
        .slice(0, 10);
}

function updateMaterialByCode(bucket, amount , customer, isRemoval) {
    if (!bucket || amount < 1) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData('material');
    if (!bucket.VALUE.COUNTS) bucket.VALUE.COUNTS = {};

    const counts = bucket.VALUE.COUNTS;
    const mult = isRemoval ? -1 : 1;

    const {name , code} = customer;
    const qty = Number(amount) || 0;
    if (code && qty > 0) {
        counts[name] = (counts[name] || 0) + (qty * mult);
        if (counts[name] <= 0) delete counts[name];
    }

    bucket.VALUE.data = Object.entries(counts)
        .map(([k, v]) => ({ name: k, value: v }))
        .sort((a, b) => b.value - a.value)
        .slice(0, 10);
}

function updateLineChart(topicRoot, timeframeKey, targetKey, keys, label, color, topicMetricRoot) {
    if (!topicRoot[timeframeKey]) topicRoot[timeframeKey] = {};
    if (!topicRoot[timeframeKey][targetKey]) topicRoot[timeframeKey][targetKey] = createEmptyData('chart');

    const chartObj = topicRoot[timeframeKey][targetKey];
    const sourceObj = topicMetricRoot[timeframeKey][targetKey];

    if (!sourceObj) return;

    const seriesData = keys.map(k => (sourceObj[k] && sourceObj[k].VALUE) ? sourceObj[k].VALUE.raw : 0);

    chartObj.data = {
        label: sourceObj.VALUE.data.label || label,
        value: sourceObj.VALUE.data.value,
        subValue: sourceObj.VALUE.data.subValue,
        xAxis: keys,
        seriesData: [{ name: label, color: color, data: seriesData }]
    };
}

function updateOrderFill(bucket, id, isFulfilled, isRemoval) {
    if (!bucket) return;

    bucket.TOTAL = bucket.TOTAL || { raw: 0, TRACKER: {} };
    bucket.FULFILLED = bucket.FULFILLED || { raw: 0, TRACKER: {} };
    bucket.VALUE = bucket.VALUE || {
        raw: 0,
        prevRaw: 0, // ← simpan nilai sebelumnya
        data: { value: "0%", label: "0 / 0", subValue: "0%" }
    };

    // ===== SIMPAN NILAI SEBELUM UPDATE =====
    const prevPercent = Number(bucket.VALUE.raw) || 0;

    // ===== TOTAL & FULFILLED =====
    const existed = bucket.TOTAL.TRACKER[id];

    if (isRemoval) {
        if (existed) {
            bucket.TOTAL.raw--;
            delete bucket.TOTAL.TRACKER[id];

            if (bucket.FULFILLED.TRACKER[id]) {
                bucket.FULFILLED.raw--;
                delete bucket.FULFILLED.TRACKER[id];
            }
        }
    } else {
        if (!existed) {
            bucket.TOTAL.raw++;
            bucket.TOTAL.TRACKER[id] = true;

            if (isFulfilled) {
                bucket.FULFILLED.raw++;
                bucket.FULFILLED.TRACKER[id] = true;
            }
        } else {
            const wasFulfilled = !!bucket.FULFILLED.TRACKER[id];
            if (isFulfilled && !wasFulfilled) {
                bucket.FULFILLED.raw++;
                bucket.FULFILLED.TRACKER[id] = true;
            }
            if (!isFulfilled && wasFulfilled) {
                bucket.FULFILLED.raw--;
                delete bucket.FULFILLED.TRACKER[id];
            }
        }
    }

    // ===== HITUNG PERSENTASE =====
    const total = bucket.TOTAL.raw;
    const done = bucket.FULFILLED.raw;

    const percent = total === 0 ? 0 : +(done / total * 100).toFixed(1);
    const diff = +(percent - prevPercent).toFixed(1);

    // ===== SET VALUE =====
    bucket.VALUE.prevRaw = prevPercent;
    bucket.VALUE.raw = percent;

    bucket.VALUE.data.value = `${percent}%`;
    bucket.VALUE.data.label = `${done} / ${total}`;
    bucket.VALUE.data.subValue =
        diff > 0 ? `+${diff}%`
            : diff < 0 ? `${diff}%`
                : `0%`;
}

// Tambahkan fungsi helper baru untuk stacked bar chart (letakkan setelah fungsi updateLineChart, sekitar baris 240)
function updateStackedBarChart(topicRoot, timeframeKey, targetKey, keys, labelPrefix, sourceTopics) {
    if (!topicRoot[timeframeKey]) topicRoot[timeframeKey] = {};
    if (!topicRoot[timeframeKey][targetKey]) {
        topicRoot[timeframeKey][targetKey] = {
            data: {
                label: "",
                xAxis: [],
                series: []
            }
        };
    }

    const chartObj = topicRoot[timeframeKey][targetKey];

    // Prepare xAxis based on timeframe
    let xAxisLabels = [];
    if (timeframeKey === 'DAILY') {
        // Format: "01/07", "02/07", etc based on current month
        const currentDate = new Date();
        const month = String(currentDate.getMonth() + 1).padStart(2, '0');
        xAxisLabels = keys.map(hour => {
            const day = String(currentDate.getDate()).padStart(2, '0');
            return `${day}/${month}`;
        });
    } else if (timeframeKey === 'WEEKLY') {
        xAxisLabels = keys.map(day => day.substring(0, 3)); // Mon, Tue, etc
    } else if (timeframeKey === 'MONTHLY') {
        xAxisLabels = keys.map(week => `Week ${week}`);
    } else if (timeframeKey === 'YEARLY') {
        xAxisLabels = keys.map(month => month.substring(0, 3)); // Jan, Feb, etc
    }

    // Build series data from source topics
    const series = sourceTopics.map(sourceTopic => {
        const sourceObj = ROOT_PO[sourceTopic.topicName][timeframeKey][targetKey];

        if (!sourceObj) {
            return {
                name: sourceTopic.label,
                color: sourceTopic.color,
                data: keys.map(() => 0)
            };
        }

        const seriesData = keys.map(k => {
            if (sourceObj[k] && sourceObj[k].VALUE) {
                return sourceObj[k].VALUE.raw || 0;
            }
            return 0;
        });

        return {
            name: sourceTopic.label,
            color: sourceTopic.color,
            data: seriesData
        };
    });

    // Calculate totals for label
    const totals = series.map(s => s.data.reduce((sum, val) => sum + val, 0));
    const labelParts = series.map((s, idx) => `${s.name}: ${fmtStandard.format(totals[idx])}`);

    chartObj.data = {
        label: labelParts.join(' | '),
        xAxis: xAxisLabels,
        series: series
    };
}

// --- 5. PROCESSOR SINGLE TRANSACTION ---
function processSingle(data, isRemoval) {
    const { bucket, amount, id, status, items, customerCode, customerName, isFulFilled, isCurrentYear, isCurrentMonth, isCurrentWeek, isToday, submission, flags, poNumber} = data;
    const { monthName, weekStr, dayName, hourStr } = bucket;

    // Definisikan timeframe beserta flag validasinya
    const updates = [
        ['YEARLY', monthName, ALL_MONTHS, "", isCurrentYear],
        ['MONTHLY', weekStr, ALL_WEEKS, "Week", isCurrentMonth],
        ['WEEKLY', dayName, ALL_DAYS, "", isCurrentWeek],
        ['DAILY', hourStr, ALL_HOURS, "Hour", isToday]
    ];

    const targets = [KEY_ALL];
    if (customerCode && customerCode !== "UNKNOWN") targets.push(customerCode);

    targets.forEach(targetKey => {
        updates.forEach(([tfKey, keyName, keysArr, lblPfx, isValidTimeframe]) => {

            // 1. PASTIKAN STRUKTUR (KEY) TERBUAT DULU (Walaupun isinya 0)
            ALL_TOPICS.forEach(topic => {
                if (!ROOT_PO[topic][tfKey]) ROOT_PO[topic][tfKey] = {};
            });

            // Init Container jika belum ada (Agar muncul nilai 0 / Rp 0)
            // if (!ROOT_PO[TOPIC_REVENUE][tfKey][targetKey]) {
            if (!ROOT_PO[TOPIC_COUNT][tfKey][targetKey]) {
                // ROOT_PO[TOPIC_REVENUE][tfKey][targetKey] = initContainer(keysArr, 'revenue', lblPfx);
                ROOT_PO[TOPIC_COUNT][tfKey][targetKey] = initContainer(keysArr, 'count', lblPfx);
                ROOT_PO[TOPIC_STATUS][tfKey][targetKey] = initContainer(keysArr, 'status', lblPfx);
                ROOT_PO[TOPIC_MATERIAL][tfKey][targetKey] = initContainer(keysArr, 'material', lblPfx);
                ROOT_PO[TOPIC_ORDER_FILL][tfKey][targetKey] = initContainer(keysArr, 'percent', lblPfx);
            }

            if (!ROOT_PO[TOPIC_10_SUPPLIER][tfKey][targetKey]) {
                ROOT_PO[TOPIC_10_SUPPLIER][tfKey][targetKey] = initContainer(keysArr, 'material', lblPfx);
            }

            if (!ROOT_PO[TOPIC_PO_CLOSSED][tfKey][targetKey]) {
                ROOT_PO[TOPIC_PO_CLOSSED][tfKey][targetKey] = initContainer(keysArr, 'count', lblPfx);
            }

            if (!ROOT_PO[TOPIC_PO_OUTSTANDING][tfKey][targetKey]) {
                ROOT_PO[TOPIC_PO_OUTSTANDING][tfKey][targetKey] = initContainer(keysArr, 'count', lblPfx);
            }

            if (!ROOT_PO[TOPIC_PO_ADDITIONAL][tfKey][targetKey]) {
                ROOT_PO[TOPIC_PO_ADDITIONAL][tfKey][targetKey] = initContainer(keysArr, 'count', lblPfx);
            }

            if (!ROOT_PO[TOPIC_PO_OVERDUE][tfKey][targetKey]) {
                ROOT_PO[TOPIC_PO_OVERDUE][tfKey][targetKey] = initContainer(keysArr, 'count', lblPfx);
            }

            if (!ROOT_PO[TOPIC_PO_ON_TIME_PURCHASE][tfKey][targetKey]) {
                ROOT_PO[TOPIC_PO_ON_TIME_PURCHASE][tfKey][targetKey] = initContainer(keysArr, 'percent', lblPfx);
            }

            if (!ROOT_PO[TOPIC_AGING][tfKey][targetKey]) {
                ROOT_PO[TOPIC_AGING][tfKey][targetKey] = initContainer(keysArr, 'material', lblPfx);
            }

            if (!ROOT_PO[TOPIC_OUTSTANDING_N_CLOSED][tfKey][targetKey]) {
                ROOT_PO[TOPIC_OUTSTANDING_N_CLOSED][tfKey][targetKey] = {
                    data: {
                        label: "",
                        xAxis: [],
                        series: []
                    }
                };
            }


            // 2. BARU CEK VALIDASI WAKTU (Hanya update angka jika waktunya tepat)
            if (isValidTimeframe) {
                // Execute Updates (Hanya jika datanya valid untuk timeframe ini)
                // updateMetric(ROOT_PO[TOPIC_REVENUE][tfKey][targetKey][keyName], amount, id, isRemoval, 'revenue');
                // updateMetric(ROOT_PO[TOPIC_REVENUE][tfKey][targetKey], amount, id, isRemoval, 'revenue'); 

                updateMetric(ROOT_PO[TOPIC_COUNT][tfKey][targetKey][keyName], amount, id, isRemoval, 'count');
                updateMetric(ROOT_PO[TOPIC_COUNT][tfKey][targetKey], amount, id, isRemoval, 'count');

                const isClosed = checkSubmissionStatus(submission, "PO_CLOSED");
                if (isClosed) {
                    updateMetric(ROOT_PO[TOPIC_PO_CLOSSED][tfKey][targetKey][keyName], isClosed, id, isRemoval, 'count');
                    updateMetric(ROOT_PO[TOPIC_PO_CLOSSED][tfKey][targetKey], isClosed, id, isRemoval, 'count');
                }

                const flagOutstanding = checkFlag(flags, "OUTSTANDING")
                if (flagOutstanding) {
                    updateMetric(ROOT_PO[TOPIC_PO_OUTSTANDING][tfKey][targetKey][keyName], isClosed, id, isRemoval, 'count');
                    updateMetric(ROOT_PO[TOPIC_PO_OUTSTANDING][tfKey][targetKey], isClosed, id, isRemoval, 'count');
                }

                const flagAdditional = checkFlag(flags, "ADDITIONAL")
                if (flagAdditional) {
                    updateMetric(ROOT_PO[TOPIC_PO_ADDITIONAL][tfKey][targetKey][keyName], isClosed, id, isRemoval, 'count');
                    updateMetric(ROOT_PO[TOPIC_PO_ADDITIONAL][tfKey][targetKey], isClosed, id, isRemoval, 'count');
                }

                const flagOverdue = checkFlag(flags, "OVERDUE")
                if (flagOverdue) {
                    updateMetric(ROOT_PO[TOPIC_PO_OVERDUE][tfKey][targetKey][keyName], isClosed, id, isRemoval, 'count');
                    updateMetric(ROOT_PO[TOPIC_PO_OVERDUE][tfKey][targetKey], isClosed, id, isRemoval, 'count');
                }

                if (status) {
                    updateStatus(ROOT_PO[TOPIC_STATUS][tfKey][targetKey][keyName], status, id, isRemoval);
                    updateStatus(ROOT_PO[TOPIC_STATUS][tfKey][targetKey], status, id, isRemoval);
                }
                if (items) {
                    updateMaterial(ROOT_PO[TOPIC_MATERIAL][tfKey][targetKey][keyName], items, isRemoval);
                    updateMaterial(ROOT_PO[TOPIC_MATERIAL][tfKey][targetKey], items, isRemoval);
                    // ON TIME PURCHASE ORDER
                    const activity = getOrderFromSubmission("WORKFLOW_PURCHASE_ORDER", "PO_CLOSED");
                    const orderSubmission = getOrderFromSubmission("WORKFLOW_PURCHASE_ORDER", submission.activityStatus)
                    if (orderSubmission?.order <= activity?.order && items.length > 0) { // batasi cuma sampai PO_CLOSED
                        const plannedTime = items[0].planned_date
                        const lastUpdated = submission?.date_updated

                        const isOntime = checkOntime(plannedTime, lastUpdated);
                        updateOrderFill(
                            ROOT_PO[TOPIC_PO_ON_TIME_PURCHASE][tfKey][targetKey][keyName],
                            id, isOntime.isOntime, isRemoval
                        );

                        updateOrderFill(
                            ROOT_PO[TOPIC_PO_ON_TIME_PURCHASE][tfKey][targetKey],
                            id, isOntime.isOntime, isRemoval
                        );
                    }
                    // END ON TIME PURCHASE ORDER

                    // TOP 10 AGING
                    if (orderSubmission?.order <= activity?.order && items.length > 0) { // batasi cuma sampai PO_CLOSED
                        const plannedTime = items[0].planned_date
                        const lastUpdated = (orderSubmission?.order === activity?.order ? submission?.date_updated : moment().format("YYYY-MM-DD hh:mm:ss") ) 
                        const diffDay = checkOntime(plannedTime, lastUpdated);
                        let countDays = -diffDay.diffDays;
                        if (countDays <= 0) {
                            countDays = 0; 
                        }

                        updateMaterialByCode(ROOT_PO[TOPIC_AGING][tfKey][targetKey][keyName], countDays, { name: ` ${poNumber} - ${customerName}`, code: id }, isRemoval);
                        updateMaterialByCode(ROOT_PO[TOPIC_AGING][tfKey][targetKey], countDays, { name: ` ${poNumber} - ${customerName}`, code: id }, isRemoval);
                    }   
                    // END TOP 10 AGING
                }

                if (amount > 0) {
                    updateMaterialByCode(ROOT_PO[TOPIC_10_SUPPLIER][tfKey][targetKey][keyName], amount, { name: customerName, code: customerCode }, isRemoval);
                    updateMaterialByCode(ROOT_PO[TOPIC_10_SUPPLIER][tfKey][targetKey], amount, { name:customerName, code:customerCode }, isRemoval);
                }

                // Sync Charts (Hanya update chart jika data berubah)
                // updateLineChart(ROOT_PO[TOPIC_LINE_REVENUE], tfKey, targetKey, keysArr, "Revenue", COLOR_BLUE, ROOT_PO[TOPIC_REVENUE]);
                updateLineChart(ROOT_PO[TOPIC_LINE_COUNT], tfKey, targetKey, keysArr, "Purchase Order", COLOR_BLUE, ROOT_PO[TOPIC_COUNT]);

                updateOrderFill(
                    ROOT_PO[TOPIC_ORDER_FILL][tfKey][targetKey][keyName],
                    id, isFulFilled, isRemoval
                );
                updateOrderFill(
                    ROOT_PO[TOPIC_ORDER_FILL][tfKey][targetKey],
                    id, isFulFilled, isRemoval
                );

                // Update Stacked Bar Chart: Outstanding & Closed
                updateStackedBarChart(
                    ROOT_PO[TOPIC_OUTSTANDING_N_CLOSED],
                    tfKey,
                    targetKey,
                    keysArr,
                    lblPfx,
                    [
                        {
                            topicName: TOPIC_PO_OUTSTANDING,
                            label: "Open (Outstanding)",
                            color: "#1E88E5" // Blue
                        },
                        {
                            topicName: TOPIC_PO_CLOSSED,
                            label: "Closed",
                            color: "#EF5350" // Red
                        }
                    ]
                );
            }
            // Jika isValidTimeframe == false, kode akan melewati blok update di atas, 
            // TAPI struktur object (key DAILY/MONTHLY) sudah terbentuk di langkah no 1 dengan nilai default 0.
        });
    });
}

// --- 6. MAIN EXECUTION LOOP ---
const transactions = Array.isArray(msg.payload) ? msg.payload : [];

transactions.forEach(tx => {
    if (tx.oldData) processSingle(tx.oldData, true);
    if (tx.newData) processSingle(tx.newData, false);
});

global.set("DASHBOARD", DASHBOARD);
msg.payload = DASHBOARD.REALTIME.PURCHASE_ORDER
return msg;

const event = msg.payload.data?.payload;
if (!event) return null;

const table = event.source?.table;
// Tambahkan 'submission' ke daftar tabel yang dipantau
if (table !== 'purchase_order' && table !== 'purchase_order_item' && table !== 'submission') return null;

const op = event.op;
const rowData = op === 'd' ? event.before : event.after;

if (!rowData) return null;

let targetOrderId = null;
let lookupBySubmission = false;

if (table === 'purchase_order') {
    targetOrderId = rowData.id;
} else if (table === 'purchase_order_item') {
    targetOrderId = rowData.purchase_order_id
} else if (table === 'submission') {
    targetOrderId = rowData.id;
    lookupBySubmission = true;  // Flag penanda
}

if (!targetOrderId) return null;

msg.cdc_target_id = targetOrderId;
msg.cdc_op = op;
msg.cdc_lookup_type = lookupBySubmission ? 'submission_id' : 'id';

return msg;

// --- GLOBAL CONTEXT ---
const DASHBOARD = global.get("DASHBOARD");

// Safety Check
if (!DASHBOARD || !DASHBOARD.REALTIME || !DASHBOARD.REALTIME.PURCHASE_ORDER) {
    node.warn("Data Dashboard Sales Order belum tersedia di Global Context");
    return null;
}

const ROOT_SO = DASHBOARD.REALTIME.PURCHASE_ORDER;
const BASE_TOPIC = "DASHBOARD/REALTIME/PURCHASE_ORDER";
const outputMsgs = [];

const VALID_TIMEFRAMES = ["YEARLY", "MONTHLY", "WEEKLY", "DAILY"];

Object.keys(ROOT_SO).forEach(metricKey => {

    // Filter internal data
    if (metricKey === "STATUS_INTERNAL") return;

    const metricData = ROOT_SO[metricKey];

    VALID_TIMEFRAMES.forEach(timeframeKey => {
        if (metricData[timeframeKey] && typeof metricData[timeframeKey] === 'object') {

            const customerContainer = metricData[timeframeKey];

            Object.keys(customerContainer).forEach(customerKey => {
                const payloadData = customerContainer[customerKey];
                const msg = {
                    topic: `${BASE_TOPIC}/${metricKey}/${timeframeKey}/${customerKey}`,
                    payload: payloadData,
                    retain: true
                };

                outputMsgs.push(msg);
            });
        }
    });
});

return [outputMsgs];

// --- LOGIC 1: REALTIME (CDC TRIGGER) ---
if (msg.cdc_target_id) {
    const targetId = msg.cdc_target_id;
    const filterField = msg.cdc_lookup_type === 'submission_id' ? 'submission_id' : 'id';

    // Config untuk Fetch Data
    msg.requestConfig = {
        items: 'arrival_order',
        method: "GET",
        datacore: "MAIN-DATACORE",
        params: {
            fields: [
                "id", "di_number", "delivery_date", "delivery_time", "date_created", 
                "delivery_number", "delivery_date_supplier",
                "flags.flag_id.code",
                "submission_id.activity_id.activity_status",
                "submission_id.date_updated",
                "submission_id.activity_id.activity_status_code",
                "submission_id.activity_id.workflow_version_id.code",
                "supplier_id",
                "arrival_order_items.material_id.code",
                "arrival_order_items.material_id.name",
                "arrival_order_items.order_qty",
                "arrival_order_items.delivery_qty",
                "arrival_order_items.qty_received",
            ],
            // Dinamic Filter Key
            filter: {
                [filterField]: { _eq: targetId }
            }
        }
    };

    msg.isRealtime = true;
} else {
    // --- LOGIC 2: INITIALIZATION (STARTUP) ---
    global.set("ARRIVAL_ORDER_CACHE", {}); 
    global.set("DASHBOARD.REALTIME.ARRIVAL_ORDER", {});

    const now = new Date();
    const currentYear = now.getFullYear();
    // const currentYear = "2025";
    const startOfYear = `${currentYear}-01-01`;
    const endOfYear = `${currentYear}-12-31`;

    msg.requestConfig = {
        items: 'arrival_order',
        method: "GET",
        datacore: "MAIN-DATACORE",
        params: {
            fields: [
                "id", "di_number", "delivery_date", "delivery_time", "date_created",
                "delivery_number", "delivery_date_supplier", "arrival_date",
                "flags.flag_id.code",
                "submission_id.activity_id.activity_status",
                "submission_id.date_updated",
                "submission_id.activity_id.activity_status_code",
