            ],
            sort: '-date_created',
            limit: -1,
            filter: {
                delivery_date: {
                    _between: [startOfYear, endOfYear]
                }
            }
        }
    };

    msg.isRealtime = false;
}

msg.items = msg.requestConfig.items;
msg.method = msg.requestConfig.method;
msg.datacore = msg.requestConfig.datacore;
msg.parameter = msg.requestConfig.params;

// node.warn(msg.requestConfig); // Debugging

return msg.requestConfig;

// Master Data Company (unchanged)
const companies = global.get("CORE.CUSTOMER") || [];
const getCustomerCode = (id) => {
    if (!id) return {};
    const company = Array.isArray(companies)
        ? companies.find(c => c.id === id)
        : Object.values(companies).find(c => c.id === id);
    return company ? company : {};
};

const rows = Array.isArray(msg.payload.data) ? msg.payload.data : [];
const clean = [];

for (const row of rows) {

    // Use delivery_date as primary, fallback to arrival_date
    const date = new Date(row.delivery_date || row.arrival_date);
    if (isNaN(date.getTime())) continue;

    const items = Array.isArray(row.arrival_order_items)
        ? row.arrival_order_items.map(item => ({
            orderQty: item.order_qty,
            deliveryQty: item.delivery_qty,
            qtyReceived: item.qty_received,
