// --- 1. SETUP CONSTANTS ---
const MONTH_NAMES = ["jan", "feb", "mar", "apr", "may", "jun", "jul", "aug", "sep", "oct", "nov", "dec"];
const DAYS = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
const now = new Date();
const currentYearVal = now.getFullYear();

// --- HELPER FUNCTIONS ---
function getWeekOfMonth(d) {
  const day = d.getUTCDate();
  const week = Math.ceil(day / 7);
  return week > 5 ? 5 : week;
}

function generateBucketData(item) {
  const d = new Date(item.date);
  if (isNaN(d.getTime())) return null;

  const itemYear = d.getFullYear();
  const itemMonth = d.getMonth();
  const itemDate = d.getDate();

  const oneJan = new Date(d.getFullYear(), 0, 1);
  const numberOfDays = Math.floor((d - oneJan) / (24 * 60 * 60 * 1000));
  const weekNum = Math.ceil((d.getDay() + 1 + numberOfDays) / 7);

  const nowOneJan = new Date(currentYearVal, 0, 1);
  const nowNumberOfDays = Math.floor((now - nowOneJan) / (24 * 60 * 60 * 1000));
  const currentWeekNum = Math.ceil((now.getDay() + 1 + nowNumberOfDays) / 7);

  const isCurrentYear = itemYear === currentYearVal;
  const isCurrentMonth = isCurrentYear && (itemMonth === now.getMonth());
  const isCurrentWeek = isCurrentYear && (weekNum === currentWeekNum);
  const isToday = isCurrentMonth && (itemDate === now.getDate());

  // 🔄 Summarize quantities from items instead of a single amount
  const totalQtyReceived = item.items.reduce((sum, i) => sum + (i.qtyReceived || 0), 0);
  const totalOrderQty = item.items.reduce((sum, i) => sum + (i.orderQty || 0), 0);
  const totalDeliveryQty = item.items.reduce((sum, i) => sum + (i.deliveryQty || 0), 0);

  return {
    bucket: {
      year: itemYear,
      monthName: MONTH_NAMES[d.getMonth()],
      weekStr: String(getWeekOfMonth(d)),
      dayName: DAYS[d.getDay()],
      hourStr: String(d.getHours()),
      dayOfMonth: d.getDate()
    },
    // 🔄 Quantities instead of amount
    totalQtyReceived,
    totalOrderQty,
    totalDeliveryQty,

    id: item.id,
    diNumber: item.diNumber,           // 🔄
    supplierCode: item.supplierCode,   // 🔄
    supplierName: item.supplierName,   // 🔄
    items: item.items || [],

    // 🔄 Status pulled from flat fields (already extracted in cleaner)
    status: item.submissionStatus || "Unknown",
    statusCode: item.submissionStatusCode || "UNKNOWN",
    workflowCode: item.workflowCode || "UNKNOWN",

    isCurrentYear,
    isCurrentMonth,
    isCurrentWeek,
    isToday,

    submission: {
      activityStatus: item.submissionStatusCode ?? "UNKNOWN",
      workflowStatus: item.workflowCode ?? "UNKNOWN",
      dateUpdated: item.submission_id?.date_updated
    },
    flags: item.flags,
  };
}

// --- 2. MAIN BATCH PROCESS ---
let AO_CACHE = global.get("ARRIVAL_ORDER_CACHE") || {};  // 🔄
const inputList = Array.isArray(msg.payload) ? msg.payload : [msg.payload];
const transactionList = [];

for (const raw of inputList) {
  if (!raw || !raw.id) continue;

  const newData = generateBucketData(raw);
  if (!newData) continue;

  const id = raw.id;
  const oldData = AO_CACHE[id] || null;  // 🔄

  transactionList.push({
    oldData: oldData ? JSON.parse(JSON.stringify(oldData)) : null,
    newData: newData
  });

  AO_CACHE[id] = newData;  // 🔄
}

// --- 3. COMMIT & OUTPUT ---
global.set("ARRIVAL_ORDER_CACHE", AO_CACHE);  // 🔄

msg.payload = transactionList;
return msg;

