// --- 3. HELPERS ---
function createEmptyData(type) {
    if (type === 'status' || type === 'material') return { COUNTS: {}, data: [] };
    if (type === 'chart') return { data: { label: "", value: "", subValue: "", xAxis: [], seriesData: [] } };
    if (type === 'pva_table') return { TRACKER: {}, VALUE: { data: [] } };
    return { raw: 0, data: { value: "0", label: "No Data", subValue: "0" } };
}

function initContainer(keys, type, labelPrefix = "") {
    if (type === 'chart')     return createEmptyData('chart');
    if (type === 'pva_table') return createEmptyData('pva_table');
    const container = { VALUE: createEmptyData(type) };
    if (keys) {
        keys.forEach(k => {
            container[k] = { VALUE: createEmptyData(type), TRACKER: {} };
            if (type !== 'status' && type !== 'material' && container[k].VALUE.data) {
                container[k].VALUE.data.label = labelPrefix ? `${labelPrefix} ${k}` : k;
            }
        });
    }
    return container;
}

function checkFlag(flags, expected) {
    return flags?.find(item => item?.flag_id?.code === expected)?.flag_id;
}

function checkOntime(plannedDate, referenceDate) {
    if (!plannedDate || !referenceDate) return { isOntime: false, diffDays: 0 };
    const dPlanned = new Date(plannedDate.slice(0, 10) + "T00:00:00");
    const dRef = new Date(referenceDate.slice(0, 10) + "T00:00:00");
    const diffDays = Math.floor((dPlanned - dRef) / (1000 * 60 * 60 * 24));
    return { isOntime: diffDays >= 0, diffDays };
}

// Extracts "DD/MM" from a date string or datetime string
function extractDayLabel(dtStr) {
    if (!dtStr) return null;
    const d = dtStr.slice(0, 10); // "YYYY-MM-DD"
    return `${d.slice(8, 10)}/${d.slice(5, 7)}`;
}

// Extracts "HH:MM" from a time string ("HH:MM:SS") or datetime string
function extractHourLabel(dtStr) {
    if (!dtStr) return null;
    // datetime: "2026-02-17T20:00:00.000Z" or "2026-02-17T20:00:00"
    // time-only: "20:00:00"
    const timePart = dtStr.includes("T") ? dtStr.split("T")[1] : dtStr;
    return timePart.slice(0, 5); // "HH:MM"
}

// --- 4. UPDATE FUNCTIONS ---

function updateMetric(bucket, amount, id, isRemoval, type) {
    if (!bucket) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData(type);
    bucket.TRACKER = bucket.TRACKER || {};

    const prevVal = bucket.TRACKER[id];
    const exists = prevVal !== undefined;
    let delta = 0;

    if (isRemoval) {
        if (exists) {
            delta = type === 'qty' ? -prevVal : -1;
            delete bucket.TRACKER[id];
        }
    } else {
        const valToAdd = type === 'qty' ? amount : 1;
        if (exists && type === 'qty') {
            delta = amount - prevVal;
            bucket.TRACKER[id] = amount;
        } else if (!exists) {
            delta = valToAdd;
            bucket.TRACKER[id] = valToAdd;
        }
    }

    if (delta !== 0) {
        bucket.VALUE.raw = (bucket.VALUE.raw || 0) + delta;
        bucket.VALUE.data.value = fmtStandard.format(bucket.VALUE.raw);
        const sign = delta > 0 ? "+" : "";
        bucket.VALUE.data.subValue = `${sign}${delta}`;
    }
}

function updateLeadTime(bucket, id, leadDays, isRemoval) {
    if (!bucket) return;
    bucket.TRACKER = bucket.TRACKER || {};
    bucket.VALUE = bucket.VALUE || { raw: 0, data: { value: "0 Days", label: "No Data", subValue: "0" } };

    if (isRemoval) {
        delete bucket.TRACKER[id];
    } else {
        bucket.TRACKER[id] = leadDays;
    }

    const allDays = Object.values(bucket.TRACKER);
    const avg = allDays.length === 0 ? 0 : Math.round(allDays.reduce((s, v) => s + v, 0) / allDays.length);
    const diff = avg - (bucket.VALUE.raw || 0);

    bucket.VALUE.raw = avg;
    bucket.VALUE.data.value = `${avg} Days`;
    bucket.VALUE.data.label = `${allDays.length} records`;
    bucket.VALUE.data.subValue = diff >= 0 ? `+${diff} days` : `${diff} days`;
}

function updateStatus(bucket, status, id, isRemoval) {
    if (!bucket) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData('status');
    bucket.TRACKER = bucket.TRACKER || {};

    const prevStat = bucket.TRACKER[id];
    let oldS = null, newS = null;

    if (isRemoval && prevStat) {
        oldS = prevStat; delete bucket.TRACKER[id];
    } else if (!isRemoval) {
        if (prevStat !== status) { oldS = prevStat; newS = status; bucket.TRACKER[id] = status; }
        else if (!prevStat) { newS = status; bucket.TRACKER[id] = status; }
    }

    const counts = bucket.VALUE.COUNTS;
    if (oldS) { counts[oldS] = (counts[oldS] || 1) - 1; if (counts[oldS] <= 0) delete counts[oldS]; }
    if (newS) { counts[newS] = (counts[newS] || 0) + 1; }
    bucket.VALUE.data = Object.entries(counts).map(([k, v]) => ({ name: k, value: v }));
}

function updateMaterial(bucket, items, isRemoval) {
    if (!bucket || !items?.length) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData('material');
    bucket.VALUE.COUNTS = bucket.VALUE.COUNTS || {};

    const counts = bucket.VALUE.COUNTS;
    const mult = isRemoval ? -1 : 1;

    items.forEach(item => {
        const name = item.materialName;
        const qty = Number(item.qtyReceived) || 0;
        if (name && qty > 0) {
            counts[name] = (counts[name] || 0) + (qty * mult);
            if (counts[name] <= 0) delete counts[name];
        }
    });

    bucket.VALUE.data = Object.entries(counts)
        .map(([k, v]) => ({ name: k, value: v }))
        .sort((a, b) => b.value - a.value)
        .slice(0, 10);
}

function updateSupplierRank(bucket, id, entity, isRemoval) {
    if (!bucket) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData('material');
    bucket.VALUE.COUNTS = bucket.VALUE.COUNTS || {};
    bucket.TRACKER = bucket.TRACKER || {};

    const { name, code } = entity;
    if (!code) return;

    const prevName = bucket.TRACKER[id];

    if (isRemoval) {
        if (prevName) {
            bucket.VALUE.COUNTS[prevName] = (bucket.VALUE.COUNTS[prevName] || 1) - 1;
            if (bucket.VALUE.COUNTS[prevName] <= 0) delete bucket.VALUE.COUNTS[prevName];
            delete bucket.TRACKER[id];
        }
    } else {
        if (prevName && prevName !== name) {
            bucket.VALUE.COUNTS[prevName] = (bucket.VALUE.COUNTS[prevName] || 1) - 1;
            if (bucket.VALUE.COUNTS[prevName] <= 0) delete bucket.VALUE.COUNTS[prevName];
        }
        if (!prevName || prevName !== name) {
            bucket.VALUE.COUNTS[name] = (bucket.VALUE.COUNTS[name] || 0) + 1;
            bucket.TRACKER[id] = name;
        }
    }

    const total = Object.values(bucket.VALUE.COUNTS).reduce((s, v) => s + v, 0);
    bucket.VALUE.data = Object.entries(bucket.VALUE.COUNTS)
        .map(([k, v]) => ({
            name:  k,
            count: v,
            value: total > 0 ? +(v / total * 100).toFixed(1) : 0
        }))
        .sort((a, b) => b.value - a.value)
        .slice(0, 10);
}

function updateOrderFill(bucket, id, isFulfilled, isRemoval) {
    if (!bucket) return;
    bucket.TOTAL     = bucket.TOTAL     || { raw: 0, TRACKER: {} };
    bucket.FULFILLED = bucket.FULFILLED || { raw: 0, TRACKER: {} };
    bucket.VALUE     = bucket.VALUE     || { raw: 0, data: { value: "0 (0%)", label: "0 / 0", subValue: "0%" } };

    const prevPercent = Number(bucket.VALUE.raw) || 0;
    const existed = bucket.TOTAL.TRACKER[id];

    if (isRemoval) {
        if (existed) {
            bucket.TOTAL.raw--;
            delete bucket.TOTAL.TRACKER[id];
            if (bucket.FULFILLED.TRACKER[id]) { bucket.FULFILLED.raw--; delete bucket.FULFILLED.TRACKER[id]; }
        }
    } else {
        if (!existed) {
            bucket.TOTAL.raw++;
            bucket.TOTAL.TRACKER[id] = true;
            if (isFulfilled) { bucket.FULFILLED.raw++; bucket.FULFILLED.TRACKER[id] = true; }
        } else {
            const wasFulfilled = !!bucket.FULFILLED.TRACKER[id];
            if (isFulfilled && !wasFulfilled)  { bucket.FULFILLED.raw++; bucket.FULFILLED.TRACKER[id] = true; }
            if (!isFulfilled && wasFulfilled)  { bucket.FULFILLED.raw--; delete bucket.FULFILLED.TRACKER[id]; }
        }
    }

    const total = bucket.TOTAL.raw;
    const done = bucket.FULFILLED.raw;
    const percent = total === 0 ? 0 : +(done / total * 100).toFixed(1);
    const diff = +(percent - prevPercent).toFixed(1);

    bucket.VALUE.raw = percent;
    bucket.VALUE.data.value = `${done} (${percent}%)`;
    bucket.VALUE.data.label = `${done} / ${total}`;
    bucket.VALUE.data.subValue = diff > 0 ? `+${diff}%` : diff < 0 ? `${diff}%` : `0%`;
}

function updateLineChart(topicRoot, timeframeKey, targetKey, keys, label, color, topicMetricRoot) {
    if (!topicRoot[timeframeKey]) topicRoot[timeframeKey] = {};
    if (!topicRoot[timeframeKey][targetKey]) topicRoot[timeframeKey][targetKey] = createEmptyData('chart');

    const chartObj = topicRoot[timeframeKey][targetKey];
    const sourceObj = topicMetricRoot[timeframeKey]?.[targetKey];
    if (!sourceObj) return;

    chartObj.data = {
        label: sourceObj.VALUE?.data?.label || label,
        value: sourceObj.VALUE?.data?.value,
        subValue: sourceObj.VALUE?.data?.subValue,
        xAxis: keys,
        seriesData: [{ name: label, color, data: keys.map(k => sourceObj[k]?.VALUE?.raw || 0) }]
    };
}

function updateLeadTimePlanActual(bucket, id, poLabel, leadDays, isRemoval) {
    if (!bucket) return;
    bucket.TRACKER = bucket.TRACKER || {};
    if (!bucket.VALUE) bucket.VALUE = { data: { stdLeadTime: STD_LEAD_TIME, xAxis: [], seriesData: [] } };

    if (isRemoval) {
        delete bucket.TRACKER[id];
    } else {
        bucket.TRACKER[id] = { label: poLabel, leadDays };
    }

    const entries  = Object.values(bucket.TRACKER);
    const xAxis    = entries.map(e => e.label);
    const actual   = entries.map(e => e.leadDays);
    const stdLine  = entries.map(() => STD_LEAD_TIME);

    let runSum = 0;
    const avgLine = entries.map((e, i) => {
        runSum += e.leadDays;
        return +(runSum / (i + 1)).toFixed(1);
    });

    bucket.VALUE.data = {
        stdLeadTime: STD_LEAD_TIME,
        xAxis,
        seriesData: [
            { name: "Actual Lead Time", type: "bar",  color: COLOR_BLUE,   data: actual  },
            { name: "Std Lead Time",    type: "line", color: COLOR_RED,    data: stdLine },
            { name: "Avg Lead Time",    type: "line", color: COLOR_YELLOW, data: avgLine }
        ]
    };
}

// ← NEW: Plan vs Actual by Day table
// TRACKER key: `${id}__${materialName}` — one entry per AO-item combination
// Each entry holds plan and actual date/hour/qty for that material line.
// On rebuild, entries are grouped by supplierName + materialName, then spread
// across day columns. Each day cell carries { plan: {hour, qty}, act: {hour, qty} }.
function updatePlanVsActualByDay(bucket, id, items, supplierName, planDateStr, planTimeStr, actDatetimeStr, isRemoval) {
    if (!bucket || !items?.length) return;
    bucket.TRACKER = bucket.TRACKER || {};

    const planDayLabel = extractDayLabel(planDateStr);
    const planHour     = extractHourLabel(planTimeStr);
    const actDayLabel  = extractDayLabel(actDatetimeStr);
    const actHour      = extractHourLabel(actDatetimeStr);

    items.forEach(item => {
        const materialName = item.materialName;
        if (!materialName) return;

        const trackerKey = `${id}__${materialName}`;
        const planQty    = Number(item.orderQty)    || 0;
        const actQty     = Number(item.qtyReceived) || 0;

        if (isRemoval) {
            delete bucket.TRACKER[trackerKey];
        } else {
            bucket.TRACKER[trackerKey] = {
                supplierName,
                materialName,
                planDayLabel,
                planHour,
                planQty,
                actDayLabel,
                actHour,
                actQty
            };
        }
    });

    // Rebuild grouped rows
    // groups shape: { [supplierName__materialName]: { supplier, material, days: { [DD/MM]: { plan, act } } } }
    const groups = {};
    Object.values(bucket.TRACKER).forEach(e => {
        const groupKey = `${e.supplierName}__${e.materialName}`;
        if (!groups[groupKey]) {
            groups[groupKey] = { supplier: e.supplierName, material: e.materialName, days: {} };
        }
        const row = groups[groupKey];

        if (e.planDayLabel) {
            if (!row.days[e.planDayLabel]) row.days[e.planDayLabel] = { plan: null, act: null };
            // accumulate plan qty across AOs for the same supplier+material+day
            const existing = row.days[e.planDayLabel].plan;
            row.days[e.planDayLabel].plan = {
                hour: e.planHour,
                qty:  (existing?.qty || 0) + e.planQty
            };
        }

        if (e.actDayLabel) {
            if (!row.days[e.actDayLabel]) row.days[e.actDayLabel] = { plan: null, act: null };
            const existing = row.days[e.actDayLabel].act;
            row.days[e.actDayLabel].act = {
                hour: e.actHour,
                qty:  (existing?.qty || 0) + e.actQty
            };
        }
    });

    bucket.VALUE = { data: Object.values(groups) };
}

// --- 5. PROCESS SINGLE ---
function processSingle(data, isRemoval) {
    const {
        bucket, id, status, items,
        supplierCode, supplierName,
        totalQtyReceived, totalOrderQty,
        arrivalDate, date,
        deliveryDate, deliveryTime,   // plan date + time
        isCurrentYear, isCurrentMonth, isCurrentWeek, isToday,
        diNumber,
        submission, flags,
    } = data;

    const { monthName, weekStr, dayName, hourStr } = bucket;
    const poLabel = diNumber || id;

    const updates = [
        ['YEARLY',  monthName, ALL_MONTHS, "",     isCurrentYear],
        ['MONTHLY', weekStr,   ALL_WEEKS,  "Week", isCurrentMonth],
        ['WEEKLY',  dayName,   ALL_DAYS,   "",     isCurrentWeek],
        ['DAILY',   hourStr,   ALL_HOURS,  "Hour", isToday]
    ];

    const targets = [KEY_ALL];
    if (supplierCode && supplierCode !== "UNKNOWN") targets.push(supplierCode);

    targets.forEach(targetKey => {
        updates.forEach(([tfKey, keyName, keysArr, lblPfx, isValidTimeframe]) => {

            // 1. ENSURE STRUCTURE EXISTS
            ALL_TOPICS.forEach(topic => {
                if (!ROOT_AO[topic][tfKey]) ROOT_AO[topic][tfKey] = {};
            });

            if (!ROOT_AO[TOPIC_COUNT][tfKey][targetKey]) {
                ROOT_AO[TOPIC_COUNT][tfKey][targetKey]         = initContainer(keysArr, 'count',    lblPfx);
                ROOT_AO[TOPIC_INBOUND_QTY][tfKey][targetKey]  = initContainer(keysArr, 'qty',      lblPfx);
                ROOT_AO[TOPIC_LEAD_TIME][tfKey][targetKey]    = initContainer(keysArr, 'count',    lblPfx);
                ROOT_AO[TOPIC_STATUS][tfKey][targetKey]       = initContainer(keysArr, 'status',   lblPfx);
                ROOT_AO[TOPIC_TOP_MATERIAL][tfKey][targetKey] = initContainer(keysArr, 'material', lblPfx);
                ROOT_AO[TOPIC_ON_TIME_FULL][tfKey][targetKey] = initContainer(keysArr, 'percent',  lblPfx);
            }

            if (!ROOT_AO[TOPIC_AO_OUTSTANDING][tfKey][targetKey])
                ROOT_AO[TOPIC_AO_OUTSTANDING][tfKey][targetKey]     = initContainer(keysArr, 'count',    lblPfx);
            if (!ROOT_AO[TOPIC_AO_OVERDUE][tfKey][targetKey])
                ROOT_AO[TOPIC_AO_OVERDUE][tfKey][targetKey]         = initContainer(keysArr, 'count',    lblPfx);
            if (!ROOT_AO[TOPIC_SUPPLIER_RANK][tfKey][targetKey])
                ROOT_AO[TOPIC_SUPPLIER_RANK][tfKey][targetKey]      = initContainer(keysArr, 'material', lblPfx);
            if (!ROOT_AO[TOPIC_LEAD_TIME_PLAN_ACT][tfKey][targetKey])
                ROOT_AO[TOPIC_LEAD_TIME_PLAN_ACT][tfKey][targetKey] = { TRACKER: {}, VALUE: { data: { stdLeadTime: STD_LEAD_TIME, xAxis: [], seriesData: [] } } };
            if (!ROOT_AO[TOPIC_PLAN_VS_ACTUAL_DAY][tfKey][targetKey])
                ROOT_AO[TOPIC_PLAN_VS_ACTUAL_DAY][tfKey][targetKey] = createEmptyData('pva_table'); // ← new

            // 2. ONLY UPDATE VALUES IF TIMEFRAME MATCHES
            if (isValidTimeframe) {

                updateMetric(ROOT_AO[TOPIC_COUNT][tfKey][targetKey][keyName], 1, id, isRemoval, 'count');
                updateMetric(ROOT_AO[TOPIC_COUNT][tfKey][targetKey], 1, id, isRemoval, 'count');

                updateMetric(ROOT_AO[TOPIC_INBOUND_QTY][tfKey][targetKey][keyName], totalQtyReceived, id, isRemoval, 'qty');
                updateMetric(ROOT_AO[TOPIC_INBOUND_QTY][tfKey][targetKey], totalQtyReceived, id, isRemoval, 'qty');

                if (arrivalDate && date) {
                    const leadDays = Math.abs(checkOntime(date, arrivalDate).diffDays);

                    updateLeadTime(ROOT_AO[TOPIC_LEAD_TIME][tfKey][targetKey][keyName], id, leadDays, isRemoval);
                    updateLeadTime(ROOT_AO[TOPIC_LEAD_TIME][tfKey][targetKey], id, leadDays, isRemoval);

                    updateLeadTimePlanActual(ROOT_AO[TOPIC_LEAD_TIME_PLAN_ACT][tfKey][targetKey], id, poLabel, leadDays, isRemoval);
                }

                if (checkFlag(flags, "OUTSTANDING")) {
                    updateMetric(ROOT_AO[TOPIC_AO_OUTSTANDING][tfKey][targetKey][keyName], 1, id, isRemoval, 'count');
                    updateMetric(ROOT_AO[TOPIC_AO_OUTSTANDING][tfKey][targetKey], 1, id, isRemoval, 'count');
                }

                if (checkFlag(flags, "OVERDUE")) {
                    updateMetric(ROOT_AO[TOPIC_AO_OVERDUE][tfKey][targetKey][keyName], 1, id, isRemoval, 'count');
                    updateMetric(ROOT_AO[TOPIC_AO_OVERDUE][tfKey][targetKey], 1, id, isRemoval, 'count');
                }

                if (status) {
                    updateStatus(ROOT_AO[TOPIC_STATUS][tfKey][targetKey][keyName], status, id, isRemoval);
                    updateStatus(ROOT_AO[TOPIC_STATUS][tfKey][targetKey], status, id, isRemoval);
                }

                if (items) {
                    updateMaterial(ROOT_AO[TOPIC_TOP_MATERIAL][tfKey][targetKey][keyName], items, isRemoval);
                    updateMaterial(ROOT_AO[TOPIC_TOP_MATERIAL][tfKey][targetKey], items, isRemoval);

                    // ← new: plan vs actual by day table
                    updatePlanVsActualByDay(
                        ROOT_AO[TOPIC_PLAN_VS_ACTUAL_DAY][tfKey][targetKey],
                        id, items, supplierName,
                        deliveryDate, deliveryTime, arrivalDate,
                        isRemoval
                    );
                }

                if (supplierCode && supplierCode !== "UNKNOWN") {
                    updateSupplierRank(ROOT_AO[TOPIC_SUPPLIER_RANK][tfKey][targetKey][keyName], id, { name: supplierName, code: supplierCode }, isRemoval);
                    updateSupplierRank(ROOT_AO[TOPIC_SUPPLIER_RANK][tfKey][targetKey], id, { name: supplierName, code: supplierCode }, isRemoval);
                }

                const isFulfilled = (totalQtyReceived || 0) >= (totalOrderQty || 1);
                updateOrderFill(ROOT_AO[TOPIC_ON_TIME_FULL][tfKey][targetKey][keyName], id, isFulfilled, isRemoval);
                updateOrderFill(ROOT_AO[TOPIC_ON_TIME_FULL][tfKey][targetKey], id, isFulfilled, isRemoval);

                updateLineChart(ROOT_AO[TOPIC_LINE_COUNT], tfKey, targetKey, keysArr, "Arrival Order", COLOR_BLUE, ROOT_AO[TOPIC_COUNT]);
            }
        });
    });
}

// --- 6. MAIN LOOP ---
const transactions = Array.isArray(msg.payload) ? msg.payload : [];
transactions.forEach(tx => {
