// --- 3. HELPERS ---
function createEmptyData(type) {
    if (type === 'status' || type === 'material') return { COUNTS: {}, data: [] };
    if (type === 'chart') return { data: { label: "", value: "", subValue: "", xAxis: [], seriesData: [] } };
    return { raw: 0, data: { value: "0", label: "No Data", subValue: "0" } };
}

function initContainer(keys, type, labelPrefix = "") {
    if (type === 'chart') return createEmptyData('chart');
    const container = { VALUE: createEmptyData(type) };
    if (keys) {
        keys.forEach(k => {
            container[k] = { VALUE: createEmptyData(type), TRACKER: {} };
            if (type !== 'status' && type !== 'material' && container[k].VALUE.data) {
                container[k].VALUE.data.label = labelPrefix ? `${labelPrefix} ${k}` : k;
            }
        });
    }
    return container;
}

function checkOntime(plannedDate, referenceDate) {
    if (!plannedDate || !referenceDate) return { isOntime: false, diffDays: 0 };
    const dPlanned = new Date(plannedDate.slice(0, 10) + "T00:00:00");
    const dRef = new Date(referenceDate.slice(0, 10) + "T00:00:00");
    const diffDays = Math.floor((dPlanned - dRef) / (1000 * 60 * 60 * 24));
    return { isOntime: diffDays >= 0, diffDays };
}

function getDayKey(isoDate) {
    if (!isoDate) return null;
    return isoDate.slice(8, 10);
}

function getDaysFromToday(isoDate) {
    if (!isoDate) return 0;
    const d = new Date(isoDate.slice(0, 10) + "T00:00:00");
    const today = new Date(new Date().toISOString().slice(0, 10) + "T00:00:00");
    return Math.floor((today - d) / (1000 * 60 * 60 * 24));
}

// --- 4. UPDATE FUNCTIONS ---

function updateMetric(bucket, amount, id, isRemoval, type) {
    if (!bucket) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData(type);
    bucket.TRACKER = bucket.TRACKER || {};

    const prevVal = bucket.TRACKER[id];
    const exists = prevVal !== undefined;
    let delta = 0;

    if (isRemoval) {
        if (exists) {
            delta = type === 'qty' ? -prevVal : -1;
            delete bucket.TRACKER[id];
        }
    } else {
        const valToAdd = type === 'qty' ? amount : 1;
        if (exists && type === 'qty') {
            delta = amount - prevVal;
            bucket.TRACKER[id] = amount;
        } else if (!exists) {
            delta = valToAdd;
            bucket.TRACKER[id] = valToAdd;
        }
    }

    if (delta !== 0) {
        bucket.VALUE.raw = (bucket.VALUE.raw || 0) + delta;
        bucket.VALUE.data.value = fmtStandard.format(bucket.VALUE.raw);
        const sign = delta > 0 ? "+" : "";
        bucket.VALUE.data.subValue = `${sign}${delta}`;
    }
}

function updateLeadTime(bucket, id, leadDays, isRemoval) {
    if (!bucket) return;
    bucket.TRACKER = bucket.TRACKER || {};
    bucket.VALUE = bucket.VALUE || { raw: 0, data: { value: "0 days", label: "No Data", subValue: "0" } };

    if (isRemoval) {
        delete bucket.TRACKER[id];
    } else {
        bucket.TRACKER[id] = leadDays;
    }

    const allDays = Object.values(bucket.TRACKER);
    const avg = allDays.length === 0 ? 0 : Math.round(allDays.reduce((s, v) => s + v, 0) / allDays.length);
    const diff = avg - (bucket.VALUE.raw || 0);

    bucket.VALUE.raw = avg;
    bucket.VALUE.data.value = `${avg} days`;
    bucket.VALUE.data.label = `${allDays.length} records`;
    bucket.VALUE.data.subValue = diff >= 0 ? `+${diff} days` : `${diff} days`;
}

function updateStatus(bucket, status, id, isRemoval) {
    if (!bucket) return;
    if (!bucket.VALUE) bucket.VALUE = createEmptyData('status');
    bucket.TRACKER = bucket.TRACKER || {};

    const prevStat = bucket.TRACKER[id];
    let oldS = null, newS = null;

    if (isRemoval && prevStat) {
        oldS = prevStat; delete bucket.TRACKER[id];
    } else if (!isRemoval) {
        if (prevStat !== status) { oldS = prevStat; newS = status; bucket.TRACKER[id] = status; }
        else if (!prevStat) { newS = status; bucket.TRACKER[id] = status; }
    }

    const counts = bucket.VALUE.COUNTS;
    if (oldS) { counts[oldS] = (counts[oldS] || 1) - 1; if (counts[oldS] <= 0) delete counts[oldS]; }
    if (newS) { counts[newS] = (counts[newS] || 0) + 1; }
    bucket.VALUE.data = Object.entries(counts).map(([k, v]) => ({ name: k, value: v }));
}

function updateOrderFill(bucket, id, isFulfilled, isRemoval) {
    if (!bucket) return;
    bucket.TOTAL     = bucket.TOTAL     || { raw: 0, TRACKER: {} };
    bucket.FULFILLED = bucket.FULFILLED || { raw: 0, TRACKER: {} };
    bucket.VALUE     = bucket.VALUE     || { raw: 0, data: { value: "0%", label: "0 / 0", subValue: "0%" } };

    const prevPercent = Number(bucket.VALUE.raw) || 0;
    const existed = bucket.TOTAL.TRACKER[id];

    if (isRemoval) {
        if (existed) {
            bucket.TOTAL.raw--;
            delete bucket.TOTAL.TRACKER[id];
            if (bucket.FULFILLED.TRACKER[id]) { bucket.FULFILLED.raw--; delete bucket.FULFILLED.TRACKER[id]; }
        }
    } else {
        if (!existed) {
            bucket.TOTAL.raw++;
            bucket.TOTAL.TRACKER[id] = true;
            if (isFulfilled) { bucket.FULFILLED.raw++; bucket.FULFILLED.TRACKER[id] = true; }
        } else {
            const wasFulfilled = !!bucket.FULFILLED.TRACKER[id];
            if (isFulfilled && !wasFulfilled)  { bucket.FULFILLED.raw++; bucket.FULFILLED.TRACKER[id] = true; }
            if (!isFulfilled && wasFulfilled)  { bucket.FULFILLED.raw--; delete bucket.FULFILLED.TRACKER[id]; }
        }
    }

    const total = bucket.TOTAL.raw;
    const done = bucket.FULFILLED.raw;
    const percent = total === 0 ? 0 : +(done / total * 100).toFixed(1);
    const diff = +(percent - prevPercent).toFixed(1);

    bucket.VALUE.raw = percent;
    bucket.VALUE.data.value = `${percent}%`;
    bucket.VALUE.data.label = `${done} / ${total}`;
    bucket.VALUE.data.subValue = diff > 0 ? `+${diff}%` : diff < 0 ? `${diff}%` : `0%`;
}

function updateLineChart(topicRoot, timeframeKey, targetKey, keys, label, color, topicMetricRoot) {
    if (!topicRoot[timeframeKey]) topicRoot[timeframeKey] = {};
    if (!topicRoot[timeframeKey][targetKey]) topicRoot[timeframeKey][targetKey] = createEmptyData('chart');

    const chartObj = topicRoot[timeframeKey][targetKey];
    const sourceObj = topicMetricRoot[timeframeKey]?.[targetKey];
    if (!sourceObj) return;

    chartObj.data = {
        label: sourceObj.VALUE?.data?.label || label,
        value: sourceObj.VALUE?.data?.value,
        subValue: sourceObj.VALUE?.data?.subValue,
        xAxis: keys,
        seriesData: [{ name: label, color, data: keys.map(k => sourceObj[k]?.VALUE?.raw || 0) }]
    };
}

function updateLineChartByDate(timeframeKey, targetKey, dayKey, id, qty, isRemoval) {
    if (!dayKey || qty < 1) return;

    const topic = ROOT_RO[TOPIC_LINE_DATE];
    if (!topic[timeframeKey]) topic[timeframeKey] = {};
    if (!topic[timeframeKey][targetKey]) {
        topic[timeframeKey][targetKey] = {
            TRACKER: {},
            COUNTS:  {},
            data: {
                label: "Replacement Order",
                value: "0",
                subValue: "0",
                xAxis: ALL_DATES,
                seriesData: [{ name: "Replacement Order", color: COLOR_BLUE, data: new Array(31).fill(0) }]
            }
        };
    }

    const bucket = topic[timeframeKey][targetKey];
    const prev = bucket.TRACKER[id];

    if (isRemoval) {
        if (prev !== undefined) {
            bucket.COUNTS[prev.dayKey] = Math.max(0, (bucket.COUNTS[prev.dayKey] || 0) - prev.qty);
            delete bucket.TRACKER[id];
        }
    } else {
        if (prev !== undefined) {
            bucket.COUNTS[prev.dayKey] = Math.max(0, (bucket.COUNTS[prev.dayKey] || 0) - prev.qty);
        }
        bucket.COUNTS[dayKey] = (bucket.COUNTS[dayKey] || 0) + qty;
        bucket.TRACKER[id] = { dayKey, qty };
    }

    const seriesData = ALL_DATES.map(d => bucket.COUNTS[d] || 0);
    const total = seriesData.reduce((s, v) => s + v, 0);
    bucket.data.value = fmtStandard.format(total);
    bucket.data.seriesData[0].data = seriesData;
}

function updateOutstandingVsClose(timeframeKey, targetKey, dayKey, id, qty, statusCode, isRemoval) {
    if (!dayKey || qty < 1) return;

    const topic = ROOT_RO[TOPIC_BAR_OUTSTANDING];
    if (!topic[timeframeKey]) topic[timeframeKey] = {};
    if (!topic[timeframeKey][targetKey]) {
        topic[timeframeKey][targetKey] = {
            TRACKER:     {},
            OUTSTANDING: {},
            CLOSED:      {},
            data: {
                label: "Outstanding Vs Close",
                value: "0",
                subValue: "0",
                xAxis: ALL_DATES,
                seriesData: [
                    { name: "Outstanding", color: COLOR_BLUE, data: new Array(31).fill(0) },
                    { name: "Closed",      color: COLOR_RED,  data: new Array(31).fill(0) }
                ]
            }
        };
    }

    const bucket    = topic[timeframeKey][targetKey];
    const isClosed  = statusCode === "RO_BINNING";
    const seriesKey = isClosed ? "CLOSED" : "OUTSTANDING";
    const prev      = bucket.TRACKER[id];

    if (isRemoval) {
        if (prev !== undefined) {
            const prevStore = prev.series === "CLOSED" ? bucket.CLOSED : bucket.OUTSTANDING;
            prevStore[prev.dayKey] = Math.max(0, (prevStore[prev.dayKey] || 0) - prev.qty);
            delete bucket.TRACKER[id];
        }
    } else {
        if (prev !== undefined) {
            const prevStore = prev.series === "CLOSED" ? bucket.CLOSED : bucket.OUTSTANDING;
            prevStore[prev.dayKey] = Math.max(0, (prevStore[prev.dayKey] || 0) - prev.qty);
        }
        const store = isClosed ? bucket.CLOSED : bucket.OUTSTANDING;
        store[dayKey] = (store[dayKey] || 0) + qty;
        bucket.TRACKER[id] = { dayKey, qty, series: seriesKey };
    }

    const outData    = ALL_DATES.map(d => bucket.OUTSTANDING[d] || 0);
    const closedData = ALL_DATES.map(d => bucket.CLOSED[d] || 0);
    const total      = [...outData, ...closedData].reduce((s, v) => s + v, 0);

    bucket.data.value              = fmtStandard.format(total);
    bucket.data.seriesData[0].data = outData;
    bucket.data.seriesData[1].data = closedData;
}

// Top 10 Replacement Item — sum order_qty per material across all timeframes
function updateTopItem(timeframeKey, targetKey, items, isRemoval) {
    if (!items?.length) return;

    const topic = ROOT_RO[TOPIC_TOP_ITEM];
    if (!topic[timeframeKey]) topic[timeframeKey] = {};
    if (!topic[timeframeKey][targetKey]) {
        topic[timeframeKey][targetKey] = {
            COUNTS: {},
            data: []
        };
    }

    const bucket = topic[timeframeKey][targetKey];
    const mult   = isRemoval ? -1 : 1;

    items.forEach(({ materialCode, materialName, orderQty }) => {
        if (!materialCode || !orderQty) return;
        const key = `${materialCode}||${materialName}`;
        bucket.COUNTS[key] = (bucket.COUNTS[key] || 0) + (orderQty * mult);
        if (bucket.COUNTS[key] <= 0) delete bucket.COUNTS[key];
    });

    bucket.data = Object.entries(bucket.COUNTS)
        .map(([k, v]) => {
            const [code, name] = k.split("||");
            return { name: `${code} - ${name}`, value: v };
        })
        .sort((a, b) => b.value - a.value)
        .slice(0, 10);
}

// Top 10 Replacement Aging — ALL orders ranked by today minus order_date (days), top 10 longest
// No status filter — every order is eligible regardless of statusCode
function updateTopAging(timeframeKey, targetKey, id, orderCode, supplierName, orderDate, isRemoval) {
    const topic = ROOT_RO[TOPIC_TOP_AGING];
    if (!topic[timeframeKey]) topic[timeframeKey] = {};
    if (!topic[timeframeKey][targetKey]) {
        topic[timeframeKey][targetKey] = {
            TRACKER: {},  // id → { orderCode, supplierName, orderDate }
            data: []
        };
    }

    const bucket = topic[timeframeKey][targetKey];

    if (isRemoval) {
        delete bucket.TRACKER[id];
    } else {
        bucket.TRACKER[id] = { orderCode, supplierName, orderDate };
    }

    bucket.data = Object.values(bucket.TRACKER)
        .map(entry => ({
            name:  `${entry.orderCode} - ${entry.supplierName}`,
            value: getDaysFromToday(entry.orderDate)
        }))
        .sort((a, b) => b.value - a.value)
        .slice(0, 10);
}

// --- 5. PROCESS SINGLE ---
function processSingle(data, isRemoval) {
    const {
        bucket, id, status, statusCode, items,
        supplierCode, supplierName, orderCode,
        totalOrderQty,
        date, orderDate,
        isCurrentYear, isCurrentMonth, isCurrentWeek, isToday,
        isOverdue,
    } = data;

    const { monthName, weekStr, dayName, hourStr } = bucket;

    const updates = [
        ['YEARLY',  monthName, ALL_MONTHS, "",     isCurrentYear],
        ['MONTHLY', weekStr,   ALL_WEEKS,  "Week", isCurrentMonth],
        ['WEEKLY',  dayName,   ALL_DAYS,   "",     isCurrentWeek],
        ['DAILY',   hourStr,   ALL_HOURS,  "Hour", isToday]
    ];

    const targets = [KEY_ALL];
    if (supplierCode && supplierCode !== "UNKNOWN") targets.push(supplierCode);

    const dayKey = getDayKey(orderDate);

    targets.forEach(targetKey => {
        updates.forEach(([tfKey, keyName, keysArr, lblPfx, isValidTimeframe]) => {

            ALL_TOPICS.forEach(topic => {
                if (!ROOT_RO[topic][tfKey]) ROOT_RO[topic][tfKey] = {};
            });

            if (!ROOT_RO[TOPIC_COUNT][tfKey][targetKey]) {
                ROOT_RO[TOPIC_COUNT][tfKey][targetKey]     = initContainer(keysArr, 'count',   lblPfx);
                ROOT_RO[TOPIC_ON_TIME][tfKey][targetKey]   = initContainer(keysArr, 'percent', lblPfx);
                ROOT_RO[TOPIC_LEAD_TIME][tfKey][targetKey] = initContainer(keysArr, 'count',   lblPfx);
                ROOT_RO[TOPIC_STATUS][tfKey][targetKey]    = initContainer(keysArr, 'status',  lblPfx);
            }

            if (!ROOT_RO[TOPIC_RO_CONFIRMED][tfKey][targetKey])
                ROOT_RO[TOPIC_RO_CONFIRMED][tfKey][targetKey] = initContainer(keysArr, 'count', lblPfx);
            if (!ROOT_RO[TOPIC_RO_CLOSED][tfKey][targetKey])
                ROOT_RO[TOPIC_RO_CLOSED][tfKey][targetKey]   = initContainer(keysArr, 'count', lblPfx);
            if (!ROOT_RO[TOPIC_RO_OVERDUE][tfKey][targetKey])
                ROOT_RO[TOPIC_RO_OVERDUE][tfKey][targetKey]  = initContainer(keysArr, 'count', lblPfx);

            if (isValidTimeframe) {

                // Total Replacement Order
                updateMetric(ROOT_RO[TOPIC_COUNT][tfKey][targetKey][keyName], 1, id, isRemoval, 'count');
                updateMetric(ROOT_RO[TOPIC_COUNT][tfKey][targetKey], 1, id, isRemoval, 'count');

                // Avg RO Lead Time
                if (date && orderDate) {
                    const leadDays = Math.abs(checkOntime(date, orderDate).diffDays);
                    updateLeadTime(ROOT_RO[TOPIC_LEAD_TIME][tfKey][targetKey][keyName], id, leadDays, isRemoval);
                    updateLeadTime(ROOT_RO[TOPIC_LEAD_TIME][tfKey][targetKey], id, leadDays, isRemoval);
                }

                // On Time Replacement
                const isOnTime = checkOntime(date, orderDate).isOntime;
                updateOrderFill(ROOT_RO[TOPIC_ON_TIME][tfKey][targetKey][keyName], id, isOnTime, isRemoval);
                updateOrderFill(ROOT_RO[TOPIC_ON_TIME][tfKey][targetKey], id, isOnTime, isRemoval);

                // RO Confirmed
                if (statusCode === "RO_DELIVERY") {
                    updateMetric(ROOT_RO[TOPIC_RO_CONFIRMED][tfKey][targetKey][keyName], 1, id, isRemoval, 'count');
                    updateMetric(ROOT_RO[TOPIC_RO_CONFIRMED][tfKey][targetKey], 1, id, isRemoval, 'count');
                }

                // RO Closed
                if (statusCode === "RO_BINNING") {
                    updateMetric(ROOT_RO[TOPIC_RO_CLOSED][tfKey][targetKey][keyName], 1, id, isRemoval, 'count');
                    updateMetric(ROOT_RO[TOPIC_RO_CLOSED][tfKey][targetKey], 1, id, isRemoval, 'count');
                }

                // RO Overdue
                if (isOverdue) {
                    updateMetric(ROOT_RO[TOPIC_RO_OVERDUE][tfKey][targetKey][keyName], 1, id, isRemoval, 'count');
                    updateMetric(ROOT_RO[TOPIC_RO_OVERDUE][tfKey][targetKey], 1, id, isRemoval, 'count');
                }

                // Status pie
                if (status) {
                    updateStatus(ROOT_RO[TOPIC_STATUS][tfKey][targetKey][keyName], status, id, isRemoval);
                    updateStatus(ROOT_RO[TOPIC_STATUS][tfKey][targetKey], status, id, isRemoval);
                }

                // Line chart by timeframe bucket
                updateLineChart(ROOT_RO[TOPIC_LINE_COUNT], tfKey, targetKey, keysArr, "Replacement Order", COLOR_BLUE, ROOT_RO[TOPIC_COUNT]);

                // MONTHLY only charts
                if (tfKey === 'MONTHLY' && dayKey && totalOrderQty > 0) {
                    updateLineChartByDate(tfKey, targetKey, dayKey, id, totalOrderQty, isRemoval);
                    updateOutstandingVsClose(tfKey, targetKey, dayKey, id, totalOrderQty, statusCode, isRemoval);
                }

                // Top 10 Replacement Item
                if (items?.length) {
                    updateTopItem(tfKey, targetKey, items, isRemoval);
                }

                // Top 10 Replacement Aging — all orders, no status filter
                if (orderDate) {
                    updateTopAging(tfKey, targetKey, id, orderCode, supplierName, orderDate, isRemoval);
                }
            }
        });
    });
}

