function formatCurrency(amount) {
    if (!amount && amount !== 0) return "-";
    const absAmount = Math.abs(amount);
    let formatted = "";
    if (absAmount >= 1000000000) {
        formatted = "Rp " + (amount / 1000000000).toFixed(1).replace('.', ',') + " Miliar";
    } else if (absAmount >= 1000000) {
        formatted = "Rp " + (amount / 1000000).toFixed(1).replace('.', ',') + " Juta";
    } else {
        formatted = "Rp " + new Intl.NumberFormat('id-ID').format(amount);
    }
    return formatted;
}

