// Helper: Lead Time Calculator
function getLeadTimeRange(submissionLogs) {
    if (!submissionLogs || !Array.isArray(submissionLogs) || submissionLogs.length === 0) return null;

    let openActivity = submissionLogs.find(l => l.activity_id?.activity_status_code === 'DO_OPEN');
    let deliveredActivity = submissionLogs.find(l => l.activity_id?.activity_status_code === 'DO_DELIVERED_TO_CUSTOMER');

    if (!openActivity || !deliveredActivity) return null;

    const openDate = new Date(openActivity.date_created);
    const deliveredDate = new Date(deliveredActivity.date_created);

    if (isNaN(openDate) || isNaN(deliveredDate)) return null;

    const diffMs = deliveredDate - openDate;
    if (diffMs < 0) return null;

    const diffHours = diffMs / (1000 * 60 * 60);
    const diffDays = diffMs / (1000 * 60 * 60 * 24);

    if (diffHours < 1) return "< 1 jam";
    if (diffHours < 6) return "1-6 jam";
    if (diffHours < 12) return "6-12 jam";
    if (diffHours < 24) return "12-24 jam";
    if (diffDays < 3) return "1-2 hari";
    if (diffDays < 7) return "3-7 hari";
    return "> 1 minggu";
}

