const fmtMiliar = new Intl.NumberFormat('id-ID', { minimumFractionDigits: 1, maximumFractionDigits: 1 });
const fmtStandard = new Intl.NumberFormat('id-ID');

function formatCurrency(amount) {
    if (!amount && amount !== 0) return "-";
    const absAmount = Math.abs(amount);
    let formatted = "";
    if (absAmount >= 1000000000) {
        formatted = "Rp " + fmtMiliar.format(amount / 1000000000) + " Miliar";
    } else if (absAmount >= 1000000) {
        formatted = "Rp " + fmtMiliar.format(amount / 1000000) + " Juta";
    } else {
        formatted = "Rp " + fmtStandard.format(amount);
    }
    return formatted;
}

function checkOntime(plannedDate, referenceDate) {
    if (!plannedDate || !referenceDate) {
        return { isOntime: false, diffDays: 0 };
    }
    const planned = plannedDate.slice(0, 10);
    const reference = referenceDate.slice(0, 10);
    const dPlanned = new Date(planned + "T00:00:00");
    const dRef = new Date(reference + "T00:00:00");
    const diffDays = Math.floor((dPlanned - dRef) / (1000 * 60 * 60 * 24));
    return {
        isOntime: diffDays >= 0, 
        diffDays: diffDays
    };
}

function checkFlag(flagList, expectedCode) {
    if (!Array.isArray(flagList)) return false;
    return flagList.some(item => item?.flag_id?.code === expectedCode);
}

