    const d = new Date(dateStr);
    if (isNaN(d.getTime())) return "-";
    const dd = String(d.getDate()).padStart(2, '0');
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const yyyy = d.getFullYear();
    const hh = String(d.getHours()).padStart(2, '0');
    const min = String(d.getMinutes()).padStart(2, '0');
    return `${dd}/${mm}/${yyyy}, HH:${min}`;
};

for (const row of rows) {
    // 1. Header
    const headerId = row.production_number ? `#${row.production_number}` : (row.code ? `#${row.code}` : "#Unknown");

    // 2. Status Badge
    // const status = row.submission_id?.activity_id?.activity_status_code || "DRAFT";

    const status = row.submission_id?.activity_id?.activity_status || "DRAFT";

    // 3. Grid Info
    const fgName = row.material_id?.name || "Unknown Product";
    const fgCode = row.material_id?.code || "-";
    const line = row.line_id || "-";

    // 4. Dates
    const prodDate = formatDate(row.production_start_date);
    const qcDate = "-"; // REQUEST: Kosong

    // 5. Quantities
    const qtyProdVal = Number(row.production_quantity) || 0;
    const qtyProd = `${qtyProdVal} pcs`;

    // QC Qty (REQUEST: 0 & Skipped)
    const qtyQC = "0 pcs";
    const qtyQCTag = "Skipped";
    const qtyQCTagColor = "blue"; // logic for frontend color if needed

    // Binning Qty (Logic: Sum from Kanbans)
    let binningVal = 0;
    if (Array.isArray(row.kanbans)) {
        binningVal = row.kanbans.reduce((acc, curr) => acc + (Number(curr.binning_qty) || 0), 0);
    }
    const qtyBinning = `${binningVal} pcs`;

    // Binning Tag Logic
    let qtyBinningTag = "Partial";
    let qtyBinningTagColor = "orange";
    if (binningVal >= qtyProdVal && qtyProdVal > 0) {
        qtyBinningTag = "Full";
        qtyBinningTagColor = "blue";
    } else if (binningVal === 0) {
        qtyBinningTag = "Empty";
        qtyBinningTagColor = "grey";
    }

    clean.push({
        id: row.id,
        // Data structure matching the UI Card Design
        ui: {
            headerId: headerId,
            status: status,

            // Top Grid
            fgName: fgName,
            fgCode: fgCode,
            line: line,

            // Date Grid
            prodDate: prodDate,
            qcDate: qcDate,

            // Bottom Boxes
            qtyProd: qtyProd,

            qtyQC: qtyQC,
            qtyQCTag: qtyQCTag,
            qtyQCTagColor: qtyQCTagColor,

            qtyBinning: qtyBinning,
            qtyBinningTag: qtyBinningTag,
            qtyBinningTagColor: qtyBinningTagColor
        },
        rawDate: row.production_start_date
    });
}

if (!clean.length) return null;
msg.payload = clean;
return msg;

