const CONTEXT_KEY = "DASHBOARD.REALTIME.PRODUCTION.SHOPPING";
let CONTEXT = global.get(CONTEXT_KEY);
let isNewContext = false;

// Inisialisasi jika Context belum ada
if (!CONTEXT) {
    CONTEXT = { LIST: {}, ARRAY: [] };
    isNewContext = true;
}

let LIST = CONTEXT.LIST || {};

const transactions = Array.isArray(msg.payload) ? msg.payload : [];
let hasChange = false;

// --- PROCESS TRANSACTIONS ---
transactions.forEach(tx => {
    if (tx.isRemoval) {
        if (LIST[tx.id]) {
            delete LIST[tx.id];
            hasChange = true;
        }
    } else {
        // Upsert
        LIST[tx.id] = tx.data;
        hasChange = true;
    }
});

// --- REBUILD ARRAY & PUBLISH IF CHANGED OR NEW CONTEXT ---
if (hasChange || isNewContext) {
    const finalArray = Object.values(LIST).map(item => ({
        id: item.id,
        ...item.ui,
        _rawDate: item.rawDate // Simpan untuk sorting
    }));

    // Sort by Date Descending
    finalArray.sort((a, b) => {
        return new Date(b._rawDate) - new Date(a._rawDate);
    });

    // Hapus field helper sorting
    const cleanArray = finalArray.map(({ _rawDate, ...keepAttrs }) => keepAttrs);

    // Update Global Object
    CONTEXT.LIST = LIST;
    CONTEXT.ARRAY = cleanArray;

    // SIMPAN KE GLOBAL
    global.set(CONTEXT_KEY, CONTEXT);

    // --- MQTT COMPATIBILITY ---
    // 1. Set Topic berdasarkan context (mengubah dot menjadi slash agar standar MQTT)
    msg.topic = CONTEXT_KEY.toUpperCase().replace(/\./g, "/");

    // 2. Set Payload (Node-RED MQTT Out akan otomatis men-stringify object ini)
    msg.payload = cleanArray;

    // 3. Opsional: Tambahkan timestamp atau metadata jika diperlukan
    // msg.retain = true; // Bisa di-set di node mqtt-out secara langsung

    return msg;
}

return null;

