// --- KONFIGURASI ---
const TARGET_WF_CODE = "WORKFLOW_SALES_ORDER";
const DASHBOARD_KEY = "DASHBOARD.CARD_STATUS.SALES_ORDER";
const CDC_TOPIC = "dashboard/data/sales_order_summary";

// 1. Validasi Input CDC
const event = msg.payload.data?.payload;
if (!event || !event.source || event.source.table !== 'submission') {
    return null; 
}

// 2. Load Global Context
const globalWorkflow = global.get('WORKFLOW');
let dashboardData = global.get(DASHBOARD_KEY);

if (!dashboardData || !dashboardData.summary) {
    // node.warn("Dashboard Data belum tersedia. Skip CDC.");
    return null;
}

// 3. Mapping: UUID -> Status Code
let targetWfVersionId = null;
let activityIdToCodeMap = {};

if (globalWorkflow && globalWorkflow[TARGET_WF_CODE]) {
    const wfObj = globalWorkflow[TARGET_WF_CODE];
    const wfVersion = wfObj.workflow_versions ? wfObj.workflow_versions[0] : null;

    if (wfVersion) {
        targetWfVersionId = wfVersion.id; 
        if (wfVersion.activities) {
            wfVersion.activities.forEach(act => {
                if (act.id) activityIdToCodeMap[act.id] = act.activity_status_code;
            });
        }
    }
}

// 4. Proses Delta Logic
const op = event.op; 
const before = event.before;
const after = event.after;

// Filter Workflow ID
const recordWfId = after ? after.workflow_version_id : (before ? before.workflow_version_id : null);
if (targetWfVersionId && recordWfId !== targetWfVersionId) return null; 

let isChanged = false;

const updateCount = (actId, delta) => {
    const code = activityIdToCodeMap[actId];
    if (code) {
        if (dashboardData.summary[code] !== undefined) {
            dashboardData.summary[code] += delta;
        } else {
            dashboardData.summary[code] = delta > 0 ? delta : 0;
        }

        const itemIndex = dashboardData.items.findIndex(i => i.code === code);
        if (itemIndex >= 0) {
            dashboardData.items[itemIndex].count = dashboardData.summary[code];
        }

        dashboardData.total += delta;
        isChanged = true;
    }
};

if (op === 'c' && after) {
    if (after.activity_id) updateCount(after.activity_id, 1);
}
else if (op === 'd' && before) {
    if (before.activity_id) updateCount(before.activity_id, -1);
}
else if (op === 'u' && before && after) {
    const oldActId = before.activity_id;
    const newActId = after.activity_id;
    if (oldActId !== newActId) {
        if (oldActId) updateCount(oldActId, -1); 
        if (newActId) updateCount(newActId, 1);  
    } else {
        return null;
    }
}

if (!isChanged) return null;

dashboardData.timestamp = new Date().toISOString();
global.set(DASHBOARD_KEY, dashboardData);

msg.topic = CDC_TOPIC;
msg.payload = dashboardData;

node.status({fill:"blue", shape:"dot", text:`CDC Update: Total ${dashboardData.total}`});

return msg;

