const TARGET_WORKFLOW = "WORKFLOW_SALES_ORDER";
const GLOBAL_STORAGE_KEY = "DASHBOARD.CARD_STATUS.SALES_ORDER";
const MQTT_TOPIC = "dashboard/data/sales_order_summary";

const globalData = global.get('WORKFLOW');
let statusMap = {};
let isMasterDataLoaded = false;

if (globalData && typeof globalData === 'object') {
    const specificWf = globalData[TARGET_WORKFLOW];
    if (specificWf && Array.isArray(specificWf.workflow_versions)) {
        const wfVersion = specificWf.workflow_versions[0];
        if (wfVersion && Array.isArray(wfVersion.activities)) {
            wfVersion.activities.forEach(act => {
                statusMap[act.activity_status_code] = {
                    count: 0,
                    label: act.activity_status,
                    code: act.activity_status_code,
                    order: parseInt(act.order) || 99
                };
            });
            isMasterDataLoaded = true;
        }
    }
}

let transactions = [];

// Handle struktur data
if (msg.payload && Array.isArray(msg.payload.data)) {
    transactions = msg.payload.data;
} else if (msg.payload && msg.payload.payload && Array.isArray(msg.payload.payload.data)) {
    transactions = msg.payload.payload.data;
}

let totalSO = 0;

transactions.forEach(item => {
    const actId = item.submission_id?.activity_id;
    const wfCode = actId?.workflow_version_id?.code;
    const statusCode = actId?.activity_status_code;

    // Filter Sales Order
    if (wfCode === TARGET_WORKFLOW && statusCode) {
        totalSO++;

        if (statusMap[statusCode]) {
            statusMap[statusCode].count++;
        } else {
            // Fallback
            statusMap[statusCode] = {
                count: 1,
                label: actId.activity_status || statusCode,
                code: statusCode,
                order: 99
            };
        }
    }
});

const outputData = {
    timestamp: new Date().toISOString(),
    total: totalSO,
    summary: {},
    items: []
};

Object.keys(statusMap).forEach(key => {
    const item = statusMap[key];
    outputData.summary[key] = item.count;
    outputData.items.push(item);
});

outputData.items.sort((a, b) => a.order - b.order);

// UPDATE GLOBAL CONTEXT (INIT)
global.set(GLOBAL_STORAGE_KEY, outputData);

msg.topic = MQTT_TOPIC;
msg.payload = outputData;

node.status({ fill: "green", shape: "dot", text: `Init: ${totalSO} items` });

return msg;

