// This function checks if a method is present in the incoming message and processes it accordingly
node.warn(msg);
if (msg.method) {
    // Construct a websocket request object
    const wsRequest = {
        type: "subscribe",
        collection: msg.items,
        query: msg.params,
        uid: msg.items // Note: Same as collection, should this be different?
    };

    // Store the link source in global context under WS collection
    global.set(`WS.COLLECTION.${msg.items}`, msg);
    global.set(`SYS.WS.GENERAL.subscription_status`,"subscribe")
    global.set(`SYS.WS.GENERAL.uid`, msg.items)
    global.set(`SYS.WS.GENERAL.last_subscribe`, new Date())
    // Send the websocket request in the output
    node.send([{ payload: JSON.stringify(wsRequest) }, null]);
} else {
    // Parse the incoming message payload
    let message = JSON.parse(msg.payload);
    global.set(`SYS.WS.GENERAL.time`, new Date())
    global.set(`SYS.WS.GENERAL.last_activity`, message.type)


    // Process different types of messages based on message type
    switch (message.type) {
        case "ping":
            // Respond to ping message with a pong message
            node.send([{ payload: { type: "pong" } }, null]);
            // Update node status to show that MAIN-DATACORE is open
            node.status({ fill: "green", shape: "ring", text: `MAIN-DATACORE open` });
            global.set(`SYS.WS.GENERAL.open`,"MAIN-DATACORE open" )
            global.set(`SYS.WS.GENERAL.last_ping`, new Date())
            break;
        case "auth":
            // Check if authentication status is OK and update node status accordingly
            if (message.status === "ok") {
                node.status({
                    fill: "green",
                    shape: "ring",
                    text: `MAIN-DATACORE authorized`,
                });
                global.set(`SYS.WS.GENERAL.authorization`,"MAIN-DATACORE authorized" )
                global.set(`SYS.WS.GENERAL.auth_time`, new Date())
            }

            node.send([null, null, {trigger:true}]);
            // Note: Message data for auth is not sent
            break;
        case "subscription":
            // Handle subscription events
            if (message.event === "init") {
                // Update node status to indicate MAIN-DATACORE INIT
                node.status({
                    fill: "green",
                    shape: "ring",
                    text: `MAIN-DATACORE INIT`,
                });
                global.set(`SYS.WS.GENERAL.init`,"MAIN-DATACORE INIT Done" )
                global.set(`SYS.WS.GENERAL.last_init`, new Date())
            }else{

            }
            // Retrieve _linkSource from global context based on message uid
            let _linkSource = global.get(`WS.COLLECTION.${message.uid}`)._linkSource;
            // Send the message and _linkSource in the output as needed
            node.send([null, { payload: message, _linkSource }]);
            break;
        default:
            // Note: Message data for other message types is not sent
            break;
    }
}

