global.set('INIT_UTIL.FUNCTION.sumArrayObject', (arr,property) => {
    // Check if input is an array
    if (!Array.isArray(arr)) {
        return 'Input is not an array';
    }

    // Sum the array of numbers
    const sum = arr.reduce((acc, curr) => acc + curr[property], 0);

    // Return the sum
    return { payload: sum };
})

global.set('INIT_UTIL.FUNCTION.maxArrayObject', (arr,property) => {
    // Check if input is an array
    if (!Array.isArray(arr)) {
        return 'Input is not an array';
    }

    // Sum the array of numbers
    const sum = arr.sort((a, b) => b[property] - a[property])

    // Return the sum
    return sum[0][property];
})

global.set('INIT_UTIL.FUNCTION.minArrayObject', (arr,property) => {
    // Check if input is an array
    if (!Array.isArray(arr)) {
        return 'Input is not an array';
    }

    // Sum the array of numbers
    const sum = arr.sort((a, b) => a[property] - b[property] )

    // Return the sum
    return sum[0][property];
})


global.set('INIT_UTIL.FUNCTION.groupBy', (array,key) => {
    // Return the end result
    return array.reduce((result, currentValue) => {
        // If an array already present for key, push it to the array. Else create an array and push the object
        (result[currentValue[key]] = result[currentValue[key]] || []).push(
            currentValue
        );
        // Return the current iteration `result` value, this will be taken as next iteration `result` value and accumulate
        return result;
    }, {}); // empty object is the initial value for result object
})


