    // make a shallow copy of payload reference, but we won't mutate it.
    // we'll compute a local replacement value per param (valueForReplace).
    for (const param of params) {
        const paramName = param.name;
        const paramType = param.type;      // e.g. 'date-time'
        const paramRequired = param.required;

        // required check
        if (paramRequired && !Object.prototype.hasOwnProperty.call(payload, paramName)) {
            throw new Error(`Parameter '${paramName}' is required but not found in payload.`);
        }

        // only attempt replacement when payload has the property
        let replacement = 'NULL';
        if (Object.prototype.hasOwnProperty.call(payload, paramName)) {
            const rawValue = payload[paramName];

            if (rawValue === null || typeof rawValue === 'undefined') {
                replacement = 'NULL';
            } else if (paramType && paramType === 'date-time') {
                // use UTC canonical format for SQL datetime and wrap in single quotes
                // moment.utc ensures consistent timezone handling
                replacement = `'${moment.utc(rawValue).format('YYYY-MM-DD HH:mm:ss')}'`;
            } else if (typeof rawValue === 'string') {
                // escape single quotes for SQL and wrap with single quotes
                const escaped = rawValue.replace(/'/g, "''");
                replacement = `'${escaped}'`;
            } else if (typeof rawValue === 'number' || typeof rawValue === 'bigint') {
                replacement = String(rawValue);
            } else if (typeof rawValue === 'boolean') {
                // convert boolean to 1/0 or true/false depending on your DB; using 1/0 here
                replacement = rawValue ? '1' : '0';
            } else {
                // fallback: stringify and quote
                const escaped = String(rawValue).replace(/'/g, "''");
                replacement = `'${escaped}'`;
            }
        } else {
            // payload doesn't have property -> keep replacement = 'NULL'
            replacement = 'NULL';
        }

        // perform replacement on query using global replace (all occurrences)
        const regex = new RegExp('\\$\\{' + paramName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\}', 'g');
        query = query.replace(regex, replacement);
    }

    return query;
});


global.set('INIT_UTIL.FUNCTION.dbQuery',(db_client, connection_param, connection_string, query) => {
    function isValidConnectionParams(db_client, connection_param, connection_string) {
        switch (db_client) {
            case "mysql":
            case "mariadb":
            case "phpmyadmin":
                return connection_param && connection_param.host && connection_param.user && connection_param.password && connection_param.database;
            case "postgresql":
                return connection_param && connection_param.host && connection_param.user && connection_param.password && connection_param.database;
            case "mssql":
                return connection_param && connection_param.server && connection_param.user && connection_param.password && connection_param.database;
            case "mongo":
                return connection_param && connection_param.host && connection_param.port && connection_param.database;
            case "oracle":
                return connection_param && connection_param.connectString && connection_param.user && connection_param.password;
            // Add validation logic for other database clients
            default:
                return false;
        }
    }

    async function runETL(db_client, connection_param, connection_string, query) {
        let dbConnection;

        try {
            // Validate connection parameters
            if (!isValidConnectionParams(db_client, connection_param, connection_string)) {
                throw new Error("Connection parameters are incomplete or invalid.");
            }

            // Initialize database connection based on the client type
            switch (db_client) {
                case "mysql":
                case "mariadb":
                    const mysql = require('mysql2/promise');
                    dbConnection = await mysql.createConnection(connection_param);
                    break;
                case "postgresql":
                    const { Client } = require('pg');
                    dbConnection = new Client(connection_param);
                    await dbConnection.connect();
                    break;
                case "mssql":
                    const sql = require('mssql');
                    dbConnection = await sql.connect(connection_param);
                    break;
                case "phpmyadmin":
                    const phpmyadmin = require('mysql2/promise');
                    dbConnection = await phpmyadmin.createConnection(connection_param);
                    break;
                case "mongo":
                    const { MongoClient } = require('mongodb');
                    dbConnection = await MongoClient.connect(connection_string, { useNewUrlParser: true, useUnifiedTopology: true });
                    break;
                case "oracle":
                    const oracle = require('oracledb');
                    dbConnection = await oracle.getConnection(connection_param);
                    break;
                default:
                    throw new Error("Unsupported database client type.");
            }

            // Execute the query
            const result = await dbConnection.query(query);
            node.status({fill:"green",shape:"ring",text:`[${msg.status}]${msg.topic} is success`})
            return result
            // Process the query results as needed
            // console.log("Query executed successfully:", result);

            // Close the database connection
            await dbConnection.close();
        } catch (error) {
            // console.error("Error executing query:", error);
            node.status({fill:"red",shape:"ring",text:`[${msg.status}]${msg.topic} - ${error.toSring()}`})
            if (dbConnection) {
                await dbConnection.close();
            }

            return error
        }
    }


    return runETL(db_client, connection_param, connection_string, query)
})

