global.set('INIT_UTIL.POST_FUNCTION.mt_shift', (payload) => {
    const shift = {
        REGULER: [],
        LONGSHIFT: []
    }
    const firstShift = {
        REGULER: "",
        LONGSHIFT: ""
    }

    const days = ["SUNDAY", "MONDAY", "TUESDAY", "WEDNESDAY", "THURSDAY", "FRIDAY", "SATURDAY"]
    payload.map(shiftData => {
        const {
            is_first_shift,
            is_overtime
        } = shiftData
        var arrDay = {}
        days.forEach(function (element) {
            arrDay[element] = []
            shiftData.repetitive_downtimes.forEach(function (itm) {
                var days = []
                JSON.parse(itm.days_of_week)?.map(item => days.push(item.toUpperCase())) || []
                if (days.includes(element)) {
                    arrDay[element].push(itm)
                }
            });
        });
        shiftData.repetitive_day = arrDay

        if (is_overtime === true) {
            shift.LONGSHIFT.push(shiftData)
            if (is_first_shift === true) {
                firstShift.LONGSHIFT = shiftData.start
            }
        } else {
            shift.REGULER.push(shiftData)
            if (is_first_shift === true) {
                firstShift.REGULER = shiftData.start
            }
        }
    })

    let result = {
        SHIFT: shift,
        FIRST_SHIFT: firstShift
    }

    global.set("SHIFT.SHIFT", shift)
    global.set("SHIFT.FIRST_SHIFT", firstShift)
    global.set('INIT_UTIL.LIST.SHIFT', moment())
    return result
})

