let generalData = [];
let monitData = [];

// Memproses bagian GENERAL secara dinamis
if (data && data.GENERAL) {
    let general = data.GENERAL;

    for (let key in general) {
        if (general.hasOwnProperty(key)) {
            generalData.push({
                "Key": key, // Kunci dinamis
                "Value": general[key] || '-' // Nilai dinamis
            });
        }
    }
}

// Memproses bagian MONIT secara dinamis
if (data && data.MONIT) {
    let monit = data.MONIT;

    // Loop melalui objek di MONIT untuk mengambil data dinamis
    for (let key in monit) {
        if (monit.hasOwnProperty(key)) {
            let processInfo = monit[key];

            // Proses setiap field di dalam objek processInfo secara dinamis
            let monitEntry = { "Process": key };

            for (let field in processInfo) {
                if (processInfo.hasOwnProperty(field)) {
                    monitEntry[field] = processInfo[field] || '-';
                }
            }

            monitData.push(monitEntry);
        }
    }
}

const connectionLog = global.get("connectionLog") ?? [];
const databaseLogData = connectionLog
    // @ts-ignore
.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp))
.map((conn) => {
    const date = new Date(conn?.timestamp);
    const optionsDate = {
        day: "2-digit",
        month: "short",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit",
        hour12: false,
        timeZone: "Asia/Jakarta" // GMT+7
    };
    // @ts-ignore
    const formattedDate = date.toLocaleString("en-GB", optionsDate).replace(",", ""); 

    return { ...conn, timestamp: formattedDate }
})

// Output ke tabel terpisah
msg.payload = {
    generalData: generalData,
    monitData: monitData
};

return [{ payload: generalData }, { payload: monitData }, { payload: databaseLogData }];

function isHostValid(connection_param) {
    return connection_param && connection_param.host ? null : 'host';
}

function isPortValid(connection_param) {
    return connection_param && connection_param.port ? null : 'port';
}

function isUsernameValid(connection_param) {
    return connection_param && connection_param.username ? null : 'username';
}

function isPasswordValid(connection_param) {
    return connection_param && connection_param.password ? null : 'password';
}

function isDatabaseValid(connection_param) {
    return connection_param && connection_param.database ? null : 'database';
}

function isQueryValid(query) {
    // return query ? null : 'query';
    return query && query.split(';').filter(cmd => cmd.trim() !== '').length === 1 ? null : 'query';
}

function isValidConnectionParams(connection_param, query) {
    const errors = [
        isHostValid(connection_param),
        isPortValid(connection_param),
        isUsernameValid(connection_param),
        isPasswordValid(connection_param),
        isDatabaseValid(connection_param),
        isQueryValid(query)
    ].filter(error => error !== null);

    return errors.length === 0 ? true : errors;
}



