const current_order = global.get(`ETL.JOB_ORDER`);



if (current_job_length === 0 && current_dc_job_length === 0) {
    node.status({ fill: "green", shape: "ring", text: `[${current_order}] Trigger Job` });
    global.set(`SYS.ETL.GENERAL.trigger_job`, `[${current_order}] Trigger Job`);
    global.set(`SYS.ETL.GENERAL.last_trigger_time`, new Date());

    const maxArrayObject = global.get(`INIT_UTIL.FUNCTION.maxArrayObject`);

    const config = env.get(`ETL_DURATION`);
    const etl_job = global.get(`CORE.ETL`);
    const replace_query_param = global.get(`INIT_UTIL.FUNCTION.replaceQueryParam`);

    let etlJobs = etl_job.filter(e =>
        e.order === current_order &&
        e.query_source &&
        e.json_source_config &&
        e.json_destination_config &&
        e.function_destination && !!global.get(`ETL.FUNCTION.${e.name}`)
    );

    const maxEtlOrder = maxArrayObject(etl_job, "order");
    const now = moment.utc();  // Use moment's UTC for current time
    const beginning_epoch = moment.utc('1970-01-01 00:00:00');  // Use UTC epoch time
    let no_etl_job = true;

    for (let i = 0; i < etlJobs.length; i++) {
        let item = etlJobs[i];
        let {
            query_source,
            json_source_config,
            name,
            last_successful_query,
            topic,
            id,
            trigger_delay
        } = item;

        const dc_connection = global.get(`CORE.ETL_CONNECTION.${item.connection_source}`);

        trigger_delay = trigger_delay || 100;

        // Handle last_successful_query, ensuring it's in UTC
        let last_query = last_successful_query ? moment.utc(last_successful_query) : beginning_epoch;

        const diff_time = now.diff(last_query, 'seconds');  // Calculate difference in seconds
        const trigger_etl = !last_successful_query ? true : diff_time >= trigger_delay;

        const payload = {
            last_successful_query: last_query.format('YYYY-MM-DD HH:mm:ss')
        };

        node.send([null, { trigger_delay, payload: !!last_successful_query, last_query: last_query.format(), diff_time, trigger_etl, now: now.format() }]);

        const query = dc_connection.db_client !== "api" ? replace_query_param(query_source, json_source_config.params, payload) : "";
        if (trigger_etl) {
            global.set(`ETL.JOB_LIST.${id}`, { status: "init", tasks: {}, payload: [], task_count: 0 });
            no_etl_job = false;

            let querySource = {
                job_name: name,
                job_details: item,
                query,
                last_successful_query: last_query.format(),
                now: now.format(),
                param_value: payload,
                status: "etl_extract",
                diff_time,
                trigger_etl,
                topic,
                id,
                db_client: dc_connection.db_client,
                connection_param: {
                    port: dc_connection.port,
                    name: dc_connection.name,
                    password: dc_connection.password,
                    username: dc_connection.username,
                    database: dc_connection.database,
                    host: dc_connection.host,
                    db_client: dc_connection.db_client,
                },
            };
            node.send(querySource);
            global.set(`SYS.ETL.GENERAL.last_successful_query`, new Date());
            global.set(`SYS.ETL.GENERAL.topic`, topic);
            global.set(`SYS.ETL.GENERAL.status`, "etl_extract");
            global.set(`SYS.ETL.GENERAL.database`, dc_connection.database);
            global.set(`SYS.ETL.GENERAL.db_client`, dc_connection.db_client);
            global.set(`SYS.ETL.MONIT.${name}.last_successful_query_extract`, new Date());
            global.set(`SYS.ETL.MONIT.${name}.topic`, topic);
            global.set(`SYS.ETL.MONIT.${name}.status`, "etl_extract");
            global.set(`SYS.ETL.MONIT.${name}.source_database`, dc_connection.database);
            global.set(`SYS.ETL.MONIT.${name}.source_db_client`, dc_connection.db_client);
            global.set(`SYS.ETL.MONIT.${name}.trigger_delay`, trigger_delay);
            global.set(`SYS.ETL.MONIT.${name}.diff_time`, diff_time);
        }
    }
    // node.send([null, { no_etl_job, maxEtlOrder ,current_order}]);
    if (no_etl_job) {
        global.set(`ETL.JOB_ORDER`, current_order >= maxEtlOrder ? 1 : current_order + 1);
        node.status({ fill: "red", shape: "ring", text: `[${current_order}] Waiting for delay, trigger next order` });
    }
} else {
    node.status({ fill: "yellow", shape: "ring", text: `[${current_order}] Job Running` });
