}else{
    // Initialize database connection based on the client type

    switch (db_client) {
        case "mysql":
            msg.server = {
                host: connection_param.host,
                port: connection_param.port,
                username: connection_param.username,
                password: connection_param.password,
                db: connection_param.database,
            }
            msg.bind = false
            msg.topic = query
            node.send([null, msg])
            break;
        case "mariadb":
            msg.server = {
                host: connection_param.host,
                port: connection_param.port,
                username: connection_param.username,
                password: connection_param.password,
                db: connection_param.database,
            }
            msg.bind = false
            msg.topic = query
            node.send([null, msg])
            break;
        case "postgresql":
            msg.pgConfig = {
                host: connection_param.host,
                port: connection_param.port,
                user: connection_param.username,
                password: connection_param.password,
                database: connection_param.database,
                application_name: "mv_core_etl" + msg.status
            }
            msg.bind = false
            msg.query = query
            node.send([null, null, msg])
            break;
        case "mssql":
            msg.payload = query
            node.send([null, null, null, msg])
            break;
        case "phpmyadmin":
            node.send([null, null, null, null, msg])
            break;
        case "mongo":
            node.send([null, null, null, null, null, msg])
            break;
        case "oracle":
            node.send([null, null, null, null, null, null, msg])

        case "api":
            msg.headers = msg.job_details.json_source_config.headers;
            msg.url = msg.job_details.json_source_config.url;
            msg.topic = msg.job_details.json_source_config.url;
            msg.method = msg.job_details.json_source_config.method;
            msg.payload = msg.job_details.json_source_config.payload;
            node.send([null, null, null, null, null, null, null, msg]);
            break;

        default:
            throw new Error("Unsupported database client type.");
    }

    // Perform validation for database clients that require it
    if (db_client !== "api") {
        const validationResult = isValidConnectionParams(connection_param, query);

        if (validationResult !== true) {
            node.send([{ validationResult, ...msg }]);
        }
    }
}

