 * Input msg.payload:
 * {
 *   rows: [...],            // data transaksi mentah
 *   chartDef: {
 *     code: "...",
 *     logic: "JS code",
 *     meta: { ... }         // optional
 *   }
 * }
 *
 * Atau kompatibel:
 * - msg.payload = [...]  (rows langsung)
 * - msg.chartDef = {...}
 *
 * Output:
 * msg.payload = {
 *   code,
 *   ts,
 *   bucket,                // hasil agregasi bucket
 *   chartData              // optional hasil finalize dari logic
 * }
 */

// =========================
// 1) CONSTANTS
// =========================
const ALL_MONTHS = ["jan", "feb", "mar", "apr", "may", "jun", "jul", "aug", "sep", "oct", "nov", "dec"];
const ALL_WEEKS = ["1", "2", "3", "4", "5"];
const ALL_DAYS = ["sunday", "monday", "tuesday", "wednesday", "thursday", "friday", "saturday"];
const ALL_HOURS = Array.from({ length: 24 }, (_, i) => String(i));

const KEY_ALL = "ALL";

// =========================
// 2) HELPERS
// =========================
function parseDateSafe(v) {
    if (!v) return null;
    const d = new Date(v);
    return isNaN(d.getTime()) ? null : d;
}

function getTimeKeys(dateObj) {
    if (!dateObj) {
        return { monthName: null, weekStr: null, dayName: null, hourStr: null };
    }

    const monthName = ALL_MONTHS[dateObj.getMonth()];
    const dayName = ALL_DAYS[dateObj.getDay()];
    const hourStr = String(dateObj.getHours());

    const dayOfMonth = dateObj.getDate();
    const weekNum = Math.min(5, Math.ceil(dayOfMonth / 7));
    const weekStr = String(weekNum);

    return { monthName, weekStr, dayName, hourStr };
}

function createBaseMetric() {
    return { raw: 0, data: { value: 0, subValue: 0 } };
}

function initContainer(keys) {
    const c = { VALUE: createBaseMetric(), TRACKER: {} };
    keys.forEach(k => {
        c[k] = { VALUE: createBaseMetric(), TRACKER: {} };
    });
    return c;
}

function ensurePath(root, timeframe, target, keys) {
    if (!root[timeframe]) root[timeframe] = {};
    if (!root[timeframe][target]) root[timeframe][target] = initContainer(keys);
}

function incMetric(metricObj, delta = 1) {
    if (!metricObj.VALUE) metricObj.VALUE = createBaseMetric();
    metricObj.VALUE.raw = (metricObj.VALUE.raw || 0) + delta;
    metricObj.VALUE.data.value = metricObj.VALUE.raw;
    metricObj.VALUE.data.subValue = delta;
}

// =========================
// 3) BUCKET CORE
// =========================
function applyDefaultCounter(bucketRoot, row, amount = 1) {
    const txDate = parseDateSafe(row.date || row.created_at || row.date_created || row.ts);
    const { monthName, weekStr, dayName, hourStr } = getTimeKeys(txDate);

    const updates = [
        ["YEARLY", monthName, ALL_MONTHS],
        ["MONTHLY", weekStr, ALL_WEEKS],
        ["WEEKLY", dayName, ALL_DAYS],
        ["DAILY", hourStr, ALL_HOURS]
    ];

    const customerCode = row.customer_code || row.customerCode || KEY_ALL;
    const targets = [KEY_ALL];
    if (customerCode && customerCode !== KEY_ALL) targets.push(customerCode);

    targets.forEach(target => {
        updates.forEach(([tf, keyName, keys]) => {
            ensurePath(bucketRoot, tf, target, keys);
            if (keyName == null) return;

            incMetric(bucketRoot[tf][target][keyName], amount);
            incMetric(bucketRoot[tf][target], amount);
        });
    });
}

// =========================
// 4) LOGIC FROM DB EXECUTOR
// =========================
/**
 * Kontrak logic DB:
 * - logic adalah JS body function.
 * - akan dipanggil per-row:
 *   fn(ctx)
 * - ctx berisi helper aman:
 *   {
 *     row, index, bucket, meta,
 *     helpers: { ensurePath, incMetric, ALL_MONTHS, ALL_WEEKS, ALL_DAYS, ALL_HOURS, KEY_ALL, getTimeKeys, parseDateSafe },
 *     state: {...} // mutable state antar-row
 *   }
 *
 * Optional finalize:
 * - jika logic mengembalikan function di row pertama via ctx.state.finalize = (bucket, state)=>any
 *   maka dipanggil setelah loop untuk menghasilkan chartData.
 */
function buildLogicExecutor(logicCode) {
    if (!logicCode || !logicCode.trim()) return null;
    try {
        // body-only JS
        return new Function("ctx", logicCode);
    } catch (e) {
        node.error("Invalid logic JS from DB: " + e.message);
        return null;
    }
}

// =========================
// 5) MAIN
// =========================
const rows = msg.payload;
const chartDef = msg.mt_chart;
const logicCode = String(chartDef.logic || "");
const meta = chartDef.meta || {};

const bucket = {};
const state = {};

const logicFn = buildLogicExecutor(logicCode);

for (let i = 0; i < rows.length; i++) {
    const row = rows[i];

    if (logicFn) {
        try {
            logicFn({
                node,
                global,
                row,
                index: i,
                bucket,
                meta,
                state,
                helpers: {
                    ensurePath,
                    incMetric,
                    ALL_MONTHS,
                    ALL_WEEKS,
                    ALL_DAYS,
                    ALL_HOURS,
                    KEY_ALL,
                    getTimeKeys,
                    parseDateSafe
                }
            });
        } catch (e) {
            node.warn(`[${chartDef.code || "UNKNOWN"}] logic runtime error row#${i}: ${e.message}`);
            // fallback tetap hitung default agar flow tidak putus
            applyDefaultCounter(bucket, row, 1);
        }
    } else {
        applyDefaultCounter(bucket, row, 1);
    }
}

// optional finalize
let chartData = null;
if (typeof state.finalize === "function") {
    try {
        chartData = state.finalize(bucket, state);
    } catch (e) {
        node.warn(`[${chartDef.code || "UNKNOWN"}] finalize error: ${e.message}`);
    }
}

msg.payload = {
    code: chartDef.code || null,
    ts: Date.now(),
    bucket,
    chartData
};

return msg;

// FIX: Implementasi lengkap — subscribe/publish setup untuk chart MQTT mode
// Kirim payload siap-format ke topic_in sesuai §3A & §6.2
const chart = msg.mt_chart;

if (!chart || !chart.topic_in) {
    node.warn('[SETUP MQTT] topic_in kosong, skip.');
    return null;
}
// Normalisasi topic: '/' → '.' sesuai standar §6
const topicNormalized = chart.topic_in.replace(/\//g, '.');
const chartData = msg.payload.chartData;

Object.keys(chartData).map((index) =>{
    // global.set(topicNormalized + `.${index}`, chartData[index])
    node.send({
        topic : topicNormalized + `.${index}`,
        payload : {
            code: chart.code,
            name: chart.name,
            data: chartData[index],   // §6.1: property 'data' berisi series
            source: 'context',
            timestamp: new Date().toISOString()
        },
        qos : 1,
        retain : true           // Retain agar subscriber baru langsung dapat data    
    }, [])
})

global.set(topicNormalized, {...chartData, bucket: msg.payload.bucket})

return [ [] , msg];

// Kirim tiap item mt_charts sebagai pesan terpisah
const items = msg.payload?.data ?? [];

if (items.length === 0) {
    node.warn('[Split Data] Tidak ada data mt_charts diterima.');
    return null;
}

node.log('[Split Data] Total charts: ' + items.length);

items.forEach(function(item) {
    node.send({
        ...msg,
        payload: item,
        mt_chart: item
    });
});

// const configDb = env.get("DATABASE");

const connection = global.get("CORE.ETL_CONNECTION")
const configDb = Object.values(connection).find(item => item.db_client == "postgresql");

// set config pg sql
msg.pgConfig = {
    user    : configDb.username,
    password: configDb.password,
    host    : configDb.host,
    database: configDb.database,
    port    : configDb.port
};

// set query
msg.query = msg.payload.query
msg.queryParameters = {...msg.filter , ...msg.filterDate}

return msg;
